import hashlib
import os
import re
import time
from functools import wraps

def cache_with_expiry(expiration_time):
    email_regex = re.compile(r'^[\w\.-]+@[\w\.-]+\.\w+$')
    def decorator(func):
        cache = {}
        salt = os.urandom(32)
        @wraps(func)
        def wrapper(*args, **kwargs):
            processed_args = []
            for arg in args:
                if isinstance(arg, str) and email_regex.match(arg):
                    hashed = hashlib.sha256(salt + arg.encode()).hexdigest()
                    processed_args.append(hashed)
                else:
                    processed_args.append(arg)
            processed_kwargs = {}
            for k, v in kwargs.items():
                if isinstance(v, str) and email_regex.match(v):
                    hashed = hashlib.sha256(salt + v.encode()).hexdigest()
                    processed_kwargs[k] = hashed
                else:
                    processed_kwargs[k] = v
            key = (tuple(processed_args), frozenset(processed_kwargs.items()))
            current_time = time.time()
            if key in cache and current_time - cache[key][0] <= expiration_time:
                return cache[key][1]
            result = func(*args, **kwargs)
            cache[key] = (current_time, result)
            return result
        return wrapper
    return decorator
