import os
import re
import argparse
from abc import ABC, abstractmethod

class FileProcessStrategy(ABC):
    @abstractmethod
    def process_file(self, filename: str) -> str:
        pass

class RegexRenameStrategy(FileProcessStrategy):
    def __init__(self, pattern: str, replacement: str):
        self.pattern = re.compile(pattern)
        self.replacement = replacement

    def process_file(self, filename: str) -> str:
        return self.pattern.sub(self.replacement, filename)

class FileRenamer:
    def __init__(self, strategy: FileProcessStrategy, directory: str, dry_run: bool):
        self.strategy = strategy
        self.directory = directory
        self.dry_run = dry_run

    def process(self):
        for filename in os.listdir(self.directory):
            src = os.path.join(self.directory, filename)
            if os.path.isfile(src):
                new_name = self.strategy.process_file(filename)
                if new_name != filename:
                    self._rename_file(src, new_name)

    def _rename_file(self, src: str, new_name: str):
        dst = os.path.join(self.directory, new_name)
        if self.dry_run:
            print(f"Dry run: {os.path.basename(src)} -> {new_name}")
        else:
            os.rename(src, dst)

def main():
    parser = argparse.ArgumentParser(description="Bulk rename files using regex patterns.")
    parser.add_argument("--dir", required=True, help="Directory containing files to rename")
    parser.add_argument("--pattern", required=True, help="Regex pattern to match")
    parser.add_argument("--replacement", required=True, help="Replacement string")
    parser.add_argument("--dry-run", action="store_true", help="Preview changes without renaming")
    args = parser.parse_args()

    strategy = RegexRenameStrategy(args.pattern, args.replacement)
    renamer = FileRenamer(strategy, args.dir, args.dry_run)
    renamer.process()

if __name__ == "__main__":
    main()
