import json

class JsonSchemaParser:
    def __init__(self):
        self.schema_data = None

    def load_schema(self, file_path):
        with open(file_path, 'r', encoding='utf-8') as file:
            self.schema_data = json.load(file)

    def parse(self):
        if self.schema_data is None:
            raise ValueError("Schema data not loaded.")
        return self._parse_element(self.schema_data)

    def _parse_element(self, element):
        if isinstance(element, dict):
            return self._parse_object(element)
        if isinstance(element, list):
            return self._parse_array(element)
        return self._parse_primitive(element)

    def _parse_object(self, obj):
        parsed = {}
        for key, value in obj.items():
            parsed[key] = self._parse_element(value)
        return {"type": "object", "properties": parsed}

    def _parse_array(self, arr):
        parsed = []
        if arr:
            parsed.append(self._parse_element(arr[0]))
        return {"type": "array", "items": parsed}

    def _parse_primitive(self, element):
        return {"type": type(element).__name__, "value": element}

    def visualize(self):
        parsed_data = self.parse()
        self._visualize_element(parsed_data)

    def _visualize_element(self, element, indent=0):
        if element["type"] == "object":
            print("  " * indent + "Object:")
            for key, value in element["properties"].items():
                print("  " * (indent + 1) + f"{key}:")
                self._visualize_element(value, indent + 2)
        elif element["type"] == "array":
            print("  " * indent + "Array:")
            for item in element["items"]:
                self._visualize_element(item, indent + 1)
        else:
            print("  " * indent + f"{element['type']}: {element['value']}")
