import heapq
import os
import hashlib

class Node:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.g = 0
        self.h = 0
        self.f = 0
        self.parent = None

    def __eq__(self, other):
        return self.x == other.x and self.y == other.y

    def __lt__(self, other):
        return self.f < other.f

    def __hash__(self):
        return hash((self.x, self.y))

def astar(grid, start, end):
    open_list = []
    closed_set = set()
    start_node = Node(start[0], start[1])
    end_node = Node(end[0], end[1])
    heapq.heappush(open_list, (start_node.f, id(start_node), start_node))

    while open_list:
        current_f, _, current_node = heapq.heappop(open_list)
        closed_set.add(current_node)

        if current_node == end_node:
            path = []
            while current_node:
                path.append((current_node.x, current_node.y))
                current_node = current_node.parent
            return path[::-1]

        neighbors = []
        for dx, dy in [(-1,0), (1,0), (0,-1), (0,1)]:
            x, y = current_node.x + dx, current_node.y + dy
            if 0 <= x < len(grid) and 0 <= y < len(grid[0]) and grid[x][y] == 0:
                neighbors.append(Node(x, y))

        for neighbor in neighbors:
            if neighbor in closed_set:
                continue
            neighbor.g = current_node.g + 1
            neighbor.h = abs(neighbor.x - end_node.x) + abs(neighbor.y - end_node.y)
            neighbor.f = neighbor.g + neighbor.h
            neighbor.parent = current_node

            for entry in open_list:
                existing_node = entry[2]
                if neighbor == existing_node and neighbor.g >= existing_node.g:
                    break
            else:
                heapq.heappush(open_list, (neighbor.f, id(neighbor), neighbor))

    return None

def anonymize_email(email):
    salt = os.urandom(32)
    email_bytes = email.encode('utf-8')
    hash_obj = hashlib.sha256(salt + email_bytes)
    return salt, hash_obj.hexdigest()
