class CacheStrategy:
    def get(self, n):
        pass

    def put(self, n, value):
        pass

class MemoizationStrategy(CacheStrategy):
    def __init__(self):
        self.cache = {}

    def get(self, n):
        return self.cache.get(n)

    def put(self, n, value):
        self.cache[n] = value

def fibonacci(n, strategy):
    if n <= 0:
        return 0
    elif n == 1:
        return 1
    cached = strategy.get(n)
    if cached is not None:
        return cached
    result = fibonacci(n-1, strategy) + fibonacci(n-2, strategy)
    strategy.put(n, result)
    return result

