class TCPStateMachine:
    def __init__(self):
        self.state = "closed"

    def handle_event(self, event):
        handler = getattr(self, f"_handle_{self.state}", self._handle_default)
        new_state = handler(event)
        if new_state is not None:
            self.state = new_state
        return self.state

    def _handle_closed(self, event):
        if event == "passive_open":
            return "listen"
        if event == "active_open":
            return "syn_sent"
        return None

    def _handle_listen(self, event):
        if event == "rcv_syn":
            return "syn_rcvd"
        if event == "close":
            return "closed"
        return None

    def _handle_syn_sent(self, event):
        if event == "rcv_syn_ack":
            return "established"
        if event == "rcv_syn":
            return "syn_rcvd"
        if event == "timeout":
            return "closed"
        return None

    def _handle_syn_rcvd(self, event):
        if event == "rcv_ack":
            return "established"
        if event == "close":
            return "fin_wait_1"
        return None

    def _handle_established(self, event):
        if event == "close":
            return "fin_wait_1"
        if event == "rcv_fin":
            return "close_wait"
        return None

    def _handle_fin_wait_1(self, event):
        if event == "rcv_ack":
            return "fin_wait_2"
        if event == "rcv_fin":
            return "closing"
        return None

    def _handle_default(self, event):
        return None
