import asyncio
import aiohttp
import hashlib
import os
import re
from bs4 import BeautifulSoup

class Anonymizer:
    @staticmethod
    def generate_salt():
        return os.urandom(32)

    @staticmethod
    def hash_email(email):
        salt = Anonymizer.generate_salt()
        salted_email = salt + email.encode()
        return (salt.hex(), hashlib.sha256(salted_email).hexdigest())

class AsyncScraper:
    def __init__(self):
        self.results = {}

    async def fetch(self, session, url):
        try:
            async with session.get(url) as response:
                return await response.text()
        except Exception as e:
            print(f"Error fetching {url}: {e}")
            return ""

    def extract_emails(self, text):
        email_pattern = r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'
        return re.findall(email_pattern, text)

    async def scrape(self, urls):
        async with aiohttp.ClientSession() as session:
            tasks = [self.process_url(session, url) for url in urls]
            await asyncio.gather(*tasks)
        return self.results

    async def process_url(self, session, url):
        html = await self.fetch(session, url)
        emails = self.extract_emails(html)
        anonymized = [Anonymizer.hash_email(email) for email in emails]
        self.results[url] = anonymized

async def main(urls):
    scraper = AsyncScraper()
    return await scraper.scrape(urls)

