import sqlite3
from abc import ABC, abstractmethod

class Observer(ABC):
    @abstractmethod
    def update(self, symbol, price):
        pass

class StockSubject:
    def __init__(self, symbol, initial_price):
        self.symbol = symbol
        self.price = initial_price
        self.observers = []
        self.conn = sqlite3.connect(':memory:')
        self.cursor = self.conn.cursor()
        self.cursor.execute('CREATE TABLE stocks (symbol TEXT, price REAL)')
        self.cursor.execute('INSERT INTO stocks VALUES (?, ?)', (symbol, initial_price))
        self.conn.commit()

    def add_observer(self, observer):
        self.observers.append(observer)

    def remove_observer(self, observer):
        self.observers.remove(observer)

    def set_price(self, new_price):
        self.price = new_price
        self.cursor.execute('UPDATE stocks SET price = ? WHERE symbol = ?', (new_price, self.symbol))
        self.conn.commit()
        self._notify_observers()

    def _notify_observers(self):
        for observer in self.observers:
            observer.update(self.symbol, self.price)

class EmailAlert(Observer):
    def update(self, symbol, price):
        print(f"Email: {symbol} is now ${price}")

class SMSAlert(Observer):
    def update(self, symbol, price):
        print(f"SMS: {symbol} updated to ${price}")

# Example usage
if __name__ == "__main__":
    stock = StockSubject("AAPL", 150.0)
    stock.add_observer(EmailAlert())
    stock.add_observer(SMSAlert())
    stock.set_price(155.0)
