import struct

class BitmapProcessor:
    def __init__(self, filename):
        self.filename = filename
        self.header = None
        self.pixel_data = bytearray()
        self.salt = os.urandom(32)

    def read_bmp(self):
        with open(self.filename, 'rb') as f:
            self.header = f.read(54)
            self.pixel_data = bytearray(f.read())

    def write_bmp(self, output_filename):
        with open(output_filename, 'wb') as f:
            f.write(self.header)
            f.write(self.pixel_data)

    def hash_email(self, email):
        hashed = hashlib.sha256(self.salt + email.encode()).hexdigest()
        return hashed.encode()

    def anonymize_email(self, email):
        hashed_email = self.hash_email(email)
        start = 0
        end = self.pixel_data.find(b'\x00', start)
        original_email = self.pixel_data[start:end]
        if original_email.decode() == email:
            self.pixel_data[start:start+len(hashed_email)] = hashed_email
            self.pixel_data[start+len(hashed_email)] = 0
