CREATE OR REPLACE FUNCTION modular_pow(base BIGINT, exponent BIGINT, modulus BIGINT) RETURNS BIGINT AS $$
DECLARE
    result BIGINT := 1;
    current_base BIGINT;
BEGIN
    IF modulus = 0 THEN RETURN 0; END IF;
    current_base := MOD(base, modulus);
    WHILE exponent > 0 LOOP
        IF exponent % 2 = 1 THEN
            result := MOD(result * current_base, modulus);
        END IF;
        current_base := MOD(current_base * current_base, modulus);
        exponent := exponent / 2;
    END LOOP;
    RETURN result;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION is_prime(n BIGINT) RETURNS BOOLEAN AS $$
DECLARE
    d BIGINT := n - 1;
    s INT := 0;
    a BIGINT;
    x BIGINT;
    i INT;
    witnesses BIGINT[] := ARRAY[2,3,5,7,11,13,17];
BEGIN
    IF n <= 1 THEN RETURN FALSE;
    ELSIF n <= 3 THEN RETURN TRUE;
    ELSIF MOD(n, 2) = 0 THEN RETURN FALSE;
    END IF;
    WHILE MOD(d, 2) = 0 LOOP
        d := d / 2;
        s := s + 1;
    END LOOP;
    FOREACH a IN ARRAY witnesses LOOP
        IF a >= n THEN CONTINUE; END IF;
        x := modular_pow(a, d, n);
        IF x = 1 OR x = n - 1 THEN CONTINUE; END IF;
        FOR i IN 1..s-1 LOOP
            x := modular_pow(x, 2, n);
            IF x = n - 1 THEN EXIT; END IF;
        END LOOP;
        IF x != n - 1 THEN RETURN FALSE; END IF;
    END LOOP;
    RETURN TRUE;
END;
$$ LANGUAGE plpgsql;
