import org.apache.kafka.clients.producer.*;
import org.apache.kafka.clients.consumer.*;
import org.apache.kafka.common.serialization.*;
import java.util.*;

public class PubSubManager {
    private final KafkaProducer<String, String> producer;

    public PubSubManager(String bootstrapServers) {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        this.producer = new KafkaProducer<>(props);
    }

    public void publish(String topic, String message) {
        producer.send(new ProducerRecord<>(topic, null, message), (metadata, exception) -> {
            if (exception != null) exception.printStackTrace();
        });
    }

    public Subscriber createSubscriber(String groupId, String bootstrapServers) {
        return new Subscriber(groupId, bootstrapServers);
    }

    public static class Subscriber implements Runnable {
        private final KafkaConsumer<String, String> consumer;
        private final List<String> topics = new ArrayList<>();
        private volatile boolean running = true;

        public Subscriber(String groupId, String bootstrapServers) {
            Properties props = new Properties();
            props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
            props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
            props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
            props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
            props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
            props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "true");
            this.consumer = new KafkaConsumer<>(props);
        }

        public void subscribeToTopic(String topic) {
            synchronized (this) {
                if (!topics.contains(topic)) {
                    topics.add(topic);
                    consumer.subscribe(topics);
                }
            }
        }

        public void stop() {
            running = false;
            consumer.wakeup();
        }

        @Override
        public void run() {
            try {
                while (running) {
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
                    for (ConsumerRecord<String, String> record : records) {
                        System.out.printf("Received message: topic=%s, value=%s%n", record.topic(), record.value());
                    }
                }
            } finally {
                consumer.close();
            }
        }
    }

    public static void main(String[] args) {
        PubSubManager manager = new PubSubManager("localhost:9092");

        // Example publisher
        manager.publish("topic1", "Hello World");

        // Example subscriber
        Subscriber subscriber = manager.createSubscriber("group1", "localhost:9092");
        subscriber.subscribeToTopic("topic1");
        new Thread(subscriber::run).start();
    }
}
