    task_routes={
        'tasks.process_task': {'queue': 'main_queue'},
        'tasks.handle_failure': {'queue': 'dead_letter_queue'}
    },
    task_acks_late=True,
    task_reject_on_worker_lost=True
)

class JobStatus:
    PENDING = 'PENDING'
    FAILED = 'FAILED'
    SUCCESS = 'SUCCESS'

jobs = {}

@celery.task(bind=True, autoretry_for=(Exception,), max_retries=3, retry_backoff=True)
def process_task(self, job_id):
    job = jobs.get(job_id)
    if not job:
        raise ValueError('Job not found')

    try:
        # Simulate task processing
        if job.get('should_fail'):
            raise Exception('Simulated failure')
        job['status'] = JobStatus.SUCCESS
    except Exception as exc:
        try:
            self.retry(countdown=self.request.retry_backoff)
        except MaxRetriesExceededError:
            job['status'] = JobStatus.FAILED
            handle_failure.delay(job_id)
        raise exc

@celery.task
def handle_failure(job_id):
    print(f"Task {job_id} moved to dead-letter queue")

@app.route('/jobs', methods=['POST'])
def create_job():
    job_id = str(uuid.uuid4())
    jobs[job_id] = {
        'id': job_id,
        'status': JobStatus.PENDING,
        'should_fail': request.json.get('should_fail', False)
    }
    process_task.delay(job_id)
    return jsonify(jobs[job_id]), 202

@app.route('/jobs/<job_id>', methods=['GET'])
def get_job(job_id):
    job = jobs.get(job_id)
    if not job:
        return jsonify({'error': 'Job not found'}), 404
    return jsonify(job)

if __name__ == '__main__':
    app.run(debug=True)
