        pass

class OutputFormat(abc.ABC):
    @classmethod
    @abc.abstractmethod
    def generate(cls, content: str, output_path: Path):
        pass

class PluginManager:
    def __init__(self):
        self.transformers = []
        self.output_formats = []

    def load_plugins(self):
        for entry in importlib.metadata.entry_points().get('markdown.transformers', []):
            self.transformers.append(entry.load())

        for entry in importlib.metadata.entry_points().get('markdown.output_formats', []):
            self.output_formats.append(entry.load())

class StaticSiteGenerator:
    def __init__(self):
        self.plugins = PluginManager()
        self.plugins.load_plugins()

    def process(self, source_dir: Path, build_dir: Path):
        for md_file in source_dir.glob('**/*.md'):
            content = md_file.read_text()

            for transformer in self.plugins.transformers:
                content = transformer.transform(content)

            for output_format in self.plugins.output_formats:
                output_path = build_dir / f"{md_file.stem}.{output_format().extension}"
                output_format.generate(content, output_path)

# Example plugin implementations (would be in separate packages)
class FooterTransformer(MarkdownTransformer):
    @classmethod
    def transform(cls, content: str) -> str:
        return content + "\n\n---\n\nGenerated by MySSG"

class HTMLOutput(OutputFormat):
    @property
    def extension(self):
        return "html"

    @classmethod
    def generate(cls, content: str, output_path: Path):
        output_path.write_text(f"<html><body>{content}</body></html>")

class PDFOutput(OutputFormat):
    @property
    def extension(self):
        return "pdf"

    @classmethod
    def generate(cls, content: str, output_path: Path):
        # Simplified PDF generation example
        import fake_pdf_lib
        fake_pdf_lib.generate(content, output_path)
