// Domain Layer (Business Entities)
public class Order
{
    public int Id { get; set; }
    public int CustomerId { get; set; }
    public DateTime OrderDate { get; set; }
    public List<OrderItem> Items { get; set; }
}

public class OrderItem
{
    public int ProductId { get; set; }
    public int Quantity { get; set; }
    public decimal Price { get; set; }
}

// Repository Interface (Abstraction Layer)
public interface IOrderRepository
{
    Order Add(Order order);
    Order GetById(int id);
}

// Service Layer (Business Logic)
public class OrderService
{
    private readonly IOrderRepository _orderRepository;

    public OrderService(IOrderRepository orderRepository)
    {
        _orderRepository = orderRepository;
    }

    public Order CreateOrder(int customerId, List<OrderItem> items)
    {
        // Business logic validation
        if (items.Count == 0)
            throw new ArgumentException("Order must contain items");

        var order = new Order
        {
            CustomerId = customerId,
            OrderDate = DateTime.UtcNow,
            Items = items
        };

        return _orderRepository.Add(order);
    }

    public Order GetOrder(int orderId)
    {
        return _orderRepository.GetById(orderId);
    }
}

// Data Access Layer (SQL Implementation)
public class SqlOrderRepository : IOrderRepository
{
    public Order Add(Order order)
    {
        using var connection = new SqlConnection("connection_string");
        connection.Open();

        // Transaction and SQL execution
        using var transaction = connection.BeginTransaction();

        // Insert order
        var orderId = connection.ExecuteScalar<int>(
            "INSERT INTO Orders (...) VALUES (...); SELECT SCOPE_IDENTITY()",
            new { order.CustomerId, order.OrderDate },
            transaction: transaction
        );

        // Insert order items
        foreach (var item in order.Items)
        {
            connection.Execute(
                "INSERT INTO OrderItems (...) VALUES (...)",
                new { OrderId = orderId, item.ProductId, item.Quantity, item.Price },
                transaction: transaction
            );
        }

        transaction.Commit();
        return GetById(orderId);
    }

    public Order GetById(int id)
    {
        using var connection = new SqlConnection("connection_string");

        var order = connection.QuerySingle<Order>(
            "SELECT * FROM Orders WHERE Id = @Id", new { Id = id }
        );

        order.Items = connection.Query<OrderItem>(
            "SELECT * FROM OrderItems WHERE OrderId = @OrderId", 
            new { OrderId = id }
        ).ToList();

        return order;
    }
}
