const { app, BrowserWindow, ipcMain, dialog } = require('electron');
const path = require('path');
const fs = require('fs');

let mainWindow;

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 800,
    height: 600,
    webPreferences: {
      nodeIntegration: true,
      contextIsolation: false
    }
  });

  mainWindow.loadFile('index.html');
}

ipcMain.on('save-file', (event, content) => {
  if (mainWindow.currentFilePath) {
    fs.writeFile(mainWindow.currentFilePath, content, (err) => {
      if (err) dialog.showErrorBox('Error', err.message);
    });
  } else {
    dialog.showSaveDialog(mainWindow, {
      defaultPath: path.join(app.getPath('documents'), 'Untitled.txt'),
      filters: [{ name: 'Text Files', extensions: ['txt'] }]
    }).then(result => {
      if (!result.canceled && result.filePath) {
        mainWindow.currentFilePath = result.filePath;
        fs.writeFile(result.filePath, content, (err) => {
          if (err) dialog.showErrorBox('Error', err.message);
        });
      }
    });
  }
});

ipcMain.on('open-file', () => {
  dialog.showOpenDialog(mainWindow, {
    properties: ['openFile'],
    filters: [{ name: 'Text Files', extensions: ['txt'] }]
  }).then(result => {
    if (!result.canceled && result.filePaths[0]) {
      const filePath = result.filePaths[0];
      fs.readFile(filePath, 'utf-8', (err, content) => {
        if (err) {
          dialog.showErrorBox('Error', err.message);
        } else {
          mainWindow.currentFilePath = filePath;
          mainWindow.webContents.send('file-opened', content, path.basename(filePath));
        }
      });
    }
  });
});

ipcMain.on('new-file', () => {
  mainWindow.currentFilePath = null;
  mainWindow.webContents.send('new-file-created');
});

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

app.on('activate', () => {
  if (BrowserWindow.getAllWindows().length === 0) createWindow();
});
