```go
package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/rs/zerolog"
	"github.com/rs/zerolog/log"
)

type Request struct {
	Data string `json:"data"`
}

func (r *Request) Validate() bool {
	return r.Data != ""
}

type ExternalResponse struct {
	Result string `json:"result"`
}

func main() {
	zerolog.TimeFieldFormat = zerolog.TimeFormatUnix
	r := chi.NewRouter()
	r.Use(middleware.Recoverer)
	r.Use(structuredLogger)
	r.Post("/process", processHandler)
	http.ListenAndServe(":8080", r)
}

func structuredLogger(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		logger := log.With().
			Str("method", r.Method).
			Str("path", r.URL.Path).
			Logger()

		logger.Info().Msg("request started")
		next.ServeHTTP(w, r)
		logger.Info().Msg("request completed")
	})
}

func processHandler(w http.ResponseWriter, r *http.Request) {
	var req Request
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		log.Error().Err(err).Msg("invalid request format")
		w.WriteHeader(http.StatusBadRequest)
		return
	}

	if !req.Validate() {
		log.Error().Interface("request", req).Msg("invalid request data")
		w.WriteHeader(http.StatusBadRequest)
		return
	}

	var result ExternalResponse
	var err error
	for i := 0; i < 3; i++ {
		result, err = callExternalAPI(req.Data)
		if err == nil {
			break
		}
		log.Warn().Err(err).Int("attempt", i+1).Msg("external API failure")
		time.Sleep(time.Duration(i+1) * 100 * time.Millisecond)
	}

	if err != nil {
		log.Error().Err(err).Msg("fallback triggered")
		result = fallbackResponse()
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(result)
}

func callExternalAPI(data string) (ExternalResponse, error) {
	return ExternalResponse{}, http.ErrServerClosed
}

func fallbackResponse() ExternalResponse {
	return ExternalResponse{Result: "fallback_data"}
}
