from sqlalchemy import create_engine, Column, String, text
from sqlalchemy.orm import sessionmaker
from sqlalchemy.ext.declarative import declarative_base
from pydantic import BaseModel
import validators
from contextlib import contextmanager
import uuid

app = FastAPI()

DATABASE_URL = os.environ.get("DATABASE_URL", "postgresql://user:pass@pgpool:5432/urls")

engine = create_engine(DATABASE_URL, pool_pre_ping=True)
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)
Base = declarative_base()

class URL(Base):
    __tablename__ = "urls"
    id = Column(String, primary_key=True, index=True)
    short_code = Column(String, unique=True, index=True)
    original_url = Column(String)

Base.metadata.create_all(bind=engine)

@contextmanager
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

class URLRequest(BaseModel):
    url: str

def generate_short_code():
    return uuid.uuid4().hex[:6]

@app.post("/shorten")
def shorten_url(request: URLRequest):
    if not validators.url(request.url):
        raise HTTPException(status_code=400, detail="Invalid URL")

    short_code = generate_short_code()
    with get_db() as db:
        db.add(URL(id=str(uuid.uuid4()), short_code=short_code, original_url=request.url))
        db.commit()
    return {"short_url": f"/{short_code}"}

@app.get("/{short_code}")
def redirect_url(short_code: str):
    with get_db() as db:
        url = db.query(URL).filter(URL.short_code == short_code).first()
        if not url:
            raise HTTPException(status_code=404, detail="URL not found")
        return {"original_url": url.original_url}

@app.get("/health")
def health_check():
    try:
        with engine.connect() as conn:
            conn.execute(text("SELECT 1"))
        return {"status": "healthy"}
    except Exception:
        return {"status": "unhealthy"}, 503
