package main

import (
	"context"
	"fmt"
	"log"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

type UserSignupEvent struct {
	UserID    string
	Email     string
	Timestamp time.Time
}

type Consumer struct {
	workers   int
	limiter   *rate.Limiter
	queue     chan UserSignupEvent
	ctx       context.Context
	waitGroup sync.WaitGroup
}

func NewConsumer(ctx context.Context, workers int, rps int) *Consumer {
	return &Consumer{
		workers: workers,
		limiter: rate.NewLimiter(rate.Limit(rps), rps),
		queue:   make(chan UserSignupEvent, 100),
		ctx:     ctx,
	}
}

func (c *Consumer) Start() {
	for i := 0; i < c.workers; i++ {
		c.waitGroup.Add(1)
		go c.worker()
	}
}

func (c *Consumer) worker() {
	defer c.waitGroup.Done()
	for {
		select {
		case <-c.ctx.Done():
			return
		case event := <-c.queue:
			if err := c.limiter.Wait(c.ctx); err != nil {
				log.Printf("Rate limit error: %v", err)
				continue
			}
			c.processEvent(event)
		}
	}
}

func (c *Consumer) processEvent(event UserSignupEvent) {
	log.Printf("Processing user %s (%s) signed up at %v", event.UserID, event.Email, event.Timestamp)
}

func (c *Consumer) Enqueue(event UserSignupEvent) error {
	select {
	case c.queue <- event:
		return nil
	case <-c.ctx.Done():
		return fmt.Errorf("consumer stopped")
	}
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	consumer := NewConsumer(ctx, 5, 100)
	consumer.Start()
	defer consumer.waitGroup.Wait()

	for i := 0; i < 10; i++ {
		consumer.Enqueue(UserSignupEvent{
			UserID:    fmt.Sprintf("user%d", i),
			Email:     fmt.Sprintf("user%d@example.com", i),
			Timestamp: time.Now(),
		})
	}

	time.Sleep(1 * time.Second)
}
