// src/main.rs
use anyhow::{anyhow, bail, Result};
use clap::{Parser, Subcommand};
use directories::ProjectDirs;
use serde::{Deserialize, Serialize};
use std::fs::File;
use std::io::{BufReader, BufWriter};
use std::path::PathBuf;

#[derive(Parser)]
#[command(name = "todo")]
#[command(version = "1.0")]
#[command(about = "A CLI task management tool", long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Add a new task
    Add {
        /// The description of the task
        description: String,
    },
    /// List all tasks
    List {
        /// Show all tasks (including completed)
        #[arg(short, long)]
        all: bool,
    },
    /// Mark a task as completed
    Complete {
        /// The ID of the task to mark as completed
        id: u32,
    },
    /// Remove a task
    Remove {
        /// The ID of the task to remove
        id: u32,
    },
}

#[derive(Debug, Serialize, Deserialize)]
struct StoredData {
    tasks: Vec<Task>,
    next_id: u32,
}

#[derive(Debug, Serialize, Deserialize)]
struct Task {
    id: u32,
    description: String,
    completed: bool,
}

fn main() -> Result<()> {
    let cli = Cli::parse();

    match cli.command {
        Commands::Add { description } => {
            let mut data = load_data()?;
            let task = Task {
                id: data.next_id,
                description,
                completed: false,
            };
            data.tasks.push(task);
            data.next_id += 1;
            save_data(&data)?;
            println!("Added task #{}", task.id);
        }
        Commands::List { all } => {
            let data = load_data()?;
            for task in &data.tasks {
                if all || !task.completed {
                    let status = if task.completed { "✓" } else { " " };
                    println!("#{} [{}] {}", task.id, status, task.description);
                }
            }
        }
        Commands::Complete { id } => {
            let mut data = load_data()?;
            if let Some(task) = data.tasks.iter_mut().find(|t| t.id == id) {
                task.completed = true;
                save_data(&data)?;
                println!("Marked task #{} as completed.", id);
            } else {
                bail!("Error: Invalid task ID '{}'. Please provide a valid task ID.", id);
            }
        }
        Commands::Remove { id } => {
            let mut data = load_data()?;
            let index = data.tasks
                .iter()
                .position(|t| t.id == id)
                .ok_or_else(|| anyhow!("Error: Invalid task ID '{}'. Please provide a valid task ID.", id))?;
            data.tasks.remove(index);
            save_data(&data)?;
            println!("Removed task #{}", id);
        }
    }

    Ok(())
}

fn get_data_path() -> Result<PathBuf> {
    let proj_dirs = ProjectDirs::from("com", "todo-cli", "todo-cli")
        .ok_or_else(|| anyhow!("Could not determine project directories"))?;
    let data_dir = proj_dirs.data_dir();
    std::fs::create_dir_all(data_dir)?;
    Ok(data_dir.join("tasks.json"))
}

fn load_data() -> Result<StoredData> {
    let data_path = get_data_path()?;
    if !data_path.exists() {
        return Ok(StoredData {
            tasks: Vec::new(),
            next_id: 1,
        });
    }
    let file = File::open(data_path)?;
    let reader = BufReader::new(file);
    let data: StoredData = serde_json::from_reader(reader)?;
    Ok(data)
}

fn save_data(data: &StoredData) -> Result<()> {
    let data_path = get_data_path()?;
    let file = File::create(data_path)?;
    let writer = BufWriter::new(file);
    serde_json::to_writer_pretty(writer, data)?;
    Ok(())
}
