import express, { Request, Response, NextFunction } from 'express';
import xss from 'xss';
import sanitize from 'express-mongo-sanitize';
import validator from 'validator';

const app = express();

const sanitizeInput = (req: Request, _: Response, next: NextFunction) => {
  sanitize.sanitize(req.body);
  sanitize.sanitize(req.query);
  sanitize.sanitize(req.params);

  const sanitizeData = (data: any): any => {
    if (typeof data === 'string') {
      return validator.escape(xss(data));
    }
    if (Array.isArray(data)) {
      return data.map(sanitizeData);
    }
    if (data instanceof Object) {
      return Object.keys(data).reduce((acc: any, key) => {
        acc[key] = sanitizeData(data[key]);
        return acc;
      }, {});
    }
    return data;
  };

  req.body = sanitizeData(req.body);
  req.query = sanitizeData(req.query);
  req.params = sanitizeData(req.params);

  next();
};

app.use(express.json());
app.use(sanitizeInput);

app.post('/test', (req: Request, res: Response) => {
  res.json({
    body: req.body,
    query: req.query,
    params: req.params
  });
});

app.listen(3000);
