import redis
import time

class NaiveProducer:
    def __init__(self):
        self.conn = redis.Redis()

    def enqueue(self, job):
        self.conn.lpush('queue', job)

class OptimizedProducer:
    def __init__(self, batch_size=100):
        self.pool = redis.ConnectionPool()
        self.batch_size = batch_size
        self.buffer = []

    def enqueue(self, job):
        self.buffer.append(job)
        if len(self.buffer) >= self.batch_size:
            self._flush()

    def _flush(self):
        if self.buffer:
            conn = redis.Redis(connection_pool=self.pool)
            conn.lpush('queue', *self.buffer)
            self.buffer.clear()

class NaiveConsumer:
    def __init__(self):
        self.conn = redis.Redis()

    def dequeue(self):
        return self.conn.rpop('queue')

class OptimizedConsumer:
    def __init__(self, batch_size=100):
        self.pool = redis.ConnectionPool()
        self.batch_size = batch_size

    def dequeue_batch(self):
        conn = redis.Redis(connection_pool=self.pool)
        with conn.pipeline() as pipe:
            for _ in range(self.batch_size):
                pipe.rpop('queue')
            return [j for j in pipe.execute() if j]

def benchmark_producer(producer_cls, num_jobs=10000, **kwargs):
    producer = producer_cls(**kwargs)
    start = time.time()
    for i in range(num_jobs):
        producer.enqueue(f'job_{i}')
    if hasattr(producer, '_flush'):
        producer._flush()
    elapsed = time.time() - start
    print(f'{producer_cls.__name__}: {num_jobs/elapsed:.2f} jobs/sec')

def benchmark_consumer(consumer_cls, num_jobs=10000, **kwargs):
    conn = redis.Redis()
    conn.delete('queue')
    conn.lpush('queue', *[f'job_{i}' for i in range(num_jobs)])

    consumer = consumer_cls(**kwargs)
    start = time.time()
    processed = 0
    while processed < num_jobs:
        jobs = consumer.dequeue_batch() if hasattr(consumer, 'dequeue_batch') else [consumer.dequeue()]
        processed += len(jobs)
    elapsed = time.time() - start
    print(f'{consumer_cls.__name__}: {num_jobs/elapsed:.2f} jobs/sec')

if __name__ == '__main__':
    print("## Producer Benchmarks ##")
    benchmark_producer(NaiveProducer)
    benchmark_producer(OptimizedProducer)

    print("\n## Consumer Benchmarks ##")
    benchmark_consumer(NaiveConsumer)
    benchmark_consumer(OptimizedConsumer)
