import zxcvbn
import requests
from argon2 import PasswordHasher
from argon2.exceptions import HashingError
import hashlib

class PasswordValidationError(Exception):
    pass

def validate_password(password):
    result = zxcvbn.zxcvbn(password)
    if result['score'] < 3:
        raise PasswordValidationError("Insufficient password strength.")

    sha1_hash = hashlib.sha1(password.encode('utf-8')).hexdigest().upper()
    prefix, suffix = sha1_hash[:5], sha1_hash[5:]
    try:
        response = requests.get(f'https://api.pwnedpasswords.com/range/{prefix}', timeout=5)
    except requests.RequestException as e:
        raise PasswordValidationError("Breach check failed.") from e

    if response.status_code != 200:
        raise PasswordValidationError("Breach check failed.")

    for line in response.text.splitlines():
        if line.split(':')[0] == suffix:
            raise PasswordValidationError("Password breached.")

    ph = PasswordHasher(time_cost=3, memory_cost=65536, parallelism=4, hash_len=32, salt_len=16)
    try:
        return ph.hash(password)
    except HashingError as e:
        raise PasswordValidationError("Hashing error.") from e
