# base.py
from abc import ABC, abstractmethod
from typing import Iterable, Any, Generic, TypeVar

T = TypeVar('T')

class Extractor(ABC, Generic[T]):
    """Abstract base class for data extraction components."""

    @abstractmethod
    def extract(self) -> Iterable[T]:
        """Yield items from a data source."""
        pass

class Transformer(ABC):
    """Abstract base class for data transformation components."""

    @abstractmethod
    def transform(self, item: Any) -> Any:
        """Process and return a single data item."""
        pass

class Loader(ABC):
    """Abstract base class for data loading components."""

    @abstractmethod
    def load(self, item: Any) -> None:
        """Persist a single transformed data item."""
        pass

class Pipeline:
    """Coordinated ETL pipeline with dependency injection."""

    def __init__(
        self,
        extractor: Extractor,
        transformer: Transformer,
        loader: Loader
    ):
        self.extractor = extractor
        self.transformer = transformer
        self.loader = loader

    def run(self) -> None:
        """Execute full ETL workflow."""
        for item in self.extractor.extract():
            transformed = self.transformer.transform(item)
            self.loader.load(transformed)
