import time

class CircuitBreaker:
    def __init__(self, failure_threshold=5, base_delay=1, consecutive_successes_needed=5):
        self.state = 'CLOSED'
        self.failure_threshold = failure_threshold
        self.base_delay = base_delay
        self.consecutive_successes_needed = consecutive_successes_needed
        self.failures = 0
        self.consecutive_successes = 0
        self.next_trial_time = 0
        self.trip_count = 0

    def execute(self, request_func):
        if self.state == 'OPEN':
            if time.monotonic() < self.next_trial_time:
                raise CircuitBreakerOpenError()
            self.state = 'HALF_OPEN'

        try:
            response = request_func()
            self._record_success()
            return response
        except Exception as e:
            self._record_failure()
            raise e

    def _record_success(self):
        if self.state == 'HALF_OPEN':
            self.consecutive_successes += 1
            if self.consecutive_successes >= self.consecutive_successes_needed:
                self.state = 'CLOSED'
                self.failures = 0
                self.consecutive_successes = 0
                self.trip_count = 0
        else:
            self.failures = 0

    def _record_failure(self):
        self.failures += 1
        if self.state == 'CLOSED' and self.failures >= self.failure_threshold:
            self._trip()
        elif self.state == 'HALF_OPEN':
            self._trip()

    def _trip(self):
        self.trip_count += 1
        self.state = 'OPEN'
        self.consecutive_successes = 0
        delay = self.base_delay * (2 ** (self.trip_count - 1))
        self.next_trial_time = time.monotonic() + delay

class CircuitBreakerOpenError(Exception):
    pass
