import hashlib
import time
from typing import Dict, List, Optional
from collections import defaultdict
import random

class Node:
    def __init__(self, address: str):
        self.address = address
        self.virtual_nodes = 200
        self.storage: Dict[str, str] = {}
        self.ring = defaultdict(list)
        self.members: Dict[str, float] = {self.address: time.time()}
        self.hash_ring: List[int] = []
        self.vnode_map: Dict[int, str] = {}

        for i in range(self.virtual_nodes):
            vnode = f"{self.address}-vnode-{i}"
            h = self._hash(vnode)
            self.vnode_map[h] = self.address
            self.hash_ring.append(h)
        self.hash_ring.sort()

    def _hash(self, key: str) -> int:
        return int(hashlib.md5(key.encode()).hexdigest(), 16) % (2**32)

    def _get_node(self, key: str) -> Optional[str]:
        h = self._hash(key)
        for vh in sorted(self.hash_ring):
            if h <= vh:
                return self.vnode_map[vh]
        return self.vnode_map[self.hash_ring[0]] if self.hash_ring else None

    def join(self, existing_node: Optional['Node'] = None):
        if existing_node:
            self.members = existing_node.members.copy()
            self.members[self.address] = time.time()
            self._update_ring(existing_node)

    def _update_ring(self, existing_node: 'Node'):
        self.hash_ring = sorted(existing_node.hash_ring + self.hash_ring)
        self.vnode_map.update(existing_node.vnode_map)
        self._redistribute_keys(existing_node)

    def _redistribute_keys(self, existing_node: 'Node'):
        for key in list(existing_node.storage.keys()):
            node = self._get_node(key)
            if node == self.address:
                self.storage[key] = existing_node.storage.pop(key)

    def leave(self):
        for vh in [h for h, addr in self.vnode_map.items() if addr == self.address]:
            del self.vnode_map[vh]
            self.hash_ring.remove(vh)
        for key in list(self.storage.keys()):
            node = self._get_node(key)
            if node and node != self.address:
                if node in self.members:
                    self._transfer_key(key, node)

    def _transfer_key(self, key: str, node_addr: str):
        pass

    def put(self, key: str, value: str):
        node_addr = self._get_node(key)
        if node_addr == self.address:
            self.storage[key] = value
        else:
            pass

    def get(self, key: str) -> Optional[str]:
        node_addr = self._get_node(key)
        if node_addr == self.address:
            return self.storage.get(key)
        return None

    def gossip(self):
        while True:
            time.sleep(1)
            alive_nodes = [addr for addr, ts in self.members.items() if time.time() - ts < 3]
            self.members = {addr: ts for addr, ts in self.members.items() if addr in alive_nodes}
            if len(self.members) > 1:
                peer = random.choice([addr for addr in self.members.keys() if addr != self.address])
                if peer:
                    self._send_gossip(peer)

    def _send_gossip(self, peer_addr: str):
        pass
