import os
from pathlib import Path
from botocore.exceptions import ClientError
from google.cloud.exceptions import NotFound

class StorageAdapter:
    def __init__(self, s3_client=None, gcs_client=None, local_base_path="."):
        self.s3_client = s3_client
        self.gcs_client = gcs_client
        self.local_base_path = Path(local_base_path)

    def upload(self, file_key, content):
        try:
            if self.s3_client:
                self.s3_client.put_object(Bucket="my-bucket", Key=file_key, Body=content)
            elif self.gcs_client:
                bucket = self.gcs_client.get_bucket("my-bucket")
                blob = bucket.blob(file_key)
                blob.upload_from_string(content)
        except Exception:
            local_path = self.local_base_path / file_key
            local_path.parent.mkdir(parents=True, exist_ok=True)
            local_path.write_text(content)

    def download(self, file_key):
        try:
            if self.s3_client:
                response = self.s3_client.get_object(Bucket="my-bucket", Key=file_key)
                return response['Body'].read().decode()
            elif self.gcs_client:
                bucket = self.gcs_client.get_bucket("my-bucket")
                blob = bucket.blob(file_key)
                return blob.download_as_text()
        except Exception:
            local_path = self.local_base_path / file_key
            return local_path.read_text()

    def delete(self, file_key):
        try:
            if self.s3_client:
                self.s3_client.delete_object(Bucket="my-bucket", Key=file_key)
            elif self.gcs_client:
                bucket = self.gcs_client.get_bucket("my-bucket")
                blob = bucket.blob(file_key)
                blob.delete()
        except Exception:
            local_path = self.local_base_path / file_key
            if local_path.exists():
                local_path.unlink()
