from prompt_toolkit import prompt
from prompt_toolkit.completion import WordCompleter
from prompt_toolkit.validation import Validator, ValidationError
from prompt_toolkit.styles import Style
from prompt_toolkit.formatted_text import HTML
from copy import deepcopy

style = Style.from_dict({
    'preview': 'ansicyan bold',
    'help': 'ansigreen italic',
})

questions = [
    {
        'key': 'environment',
        'prompt': 'Environment (Production/Staging/Development): ',
        'completer': WordCompleter(['Production', 'Staging', 'Development']),
        'validator': lambda x: x in ['Production', 'Staging', 'Development'],
        'help': 'Select deployment environment (Production, Staging, Development)'
    },
    {
        'key': 'port',
        'prompt': 'Port number (1-65535): ',
        'validator': lambda x: x.isdigit() and 1 <= int(x) <= 65535,
        'help': 'Enter valid port number between 1 and 65535'
    },
    {
        'key': 'domain',
        'prompt': 'Domain name: ',
        'validator': lambda x: len(x) > 0 and '.' in x and ' ' not in x,
        'help': 'Enter valid domain name (e.g. "example.com")'
    }
]

config = {}
undo_stack = []
redo_stack = []
current_step = 0

class CommandValidator(Validator):
    def validate(self, document):
        text = document.text
        if text in ('help', 'undo', 'redo'):
            return
        question = questions[current_step]
        if not question['validator'](text):
            raise ValidationError(message='Invalid input')

def print_preview():
    preview = HTML("\n<preview>Current configuration:\n" +
                   "\n".join(f"{q['key']}: {config.get(q['key'], 'unset')}" 
                            for q in questions) + "</preview>\n")
    print(style.format_as_html(preview))

while current_step < len(questions):
    q = questions[current_step]
    completer = q.get('completer', None)

    while True:
        try:
            answer = prompt(
                q['prompt'],
                completer=completer,
                validator=CommandValidator(),
                style=style
            )

            if answer == 'help':
                print(style.format_as_html(HTML(f"<help>Help: {q['help']}</help>")))
                continue

            elif answer == 'undo':
                if undo_stack:
                    redo_stack.append((deepcopy(config), current_step))
                    config, current_step = undo_stack.pop()
                    print_preview()
                continue

            elif answer == 'redo':
                if redo_stack:
                    undo_stack.append((deepcopy(config), current_step))
                    config, current_step = redo_stack.pop()
                    print_preview()
                continue

            if q['validator'](answer):
                undo_stack.append((deepcopy(config), current_step))
                config[q['key']] = answer
                current_step += 1
                print_preview()
                break

        except ValidationError:
            pass
