from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any, Dict, Callable, List

class EventBus:
    def __init__(self):
        self._listeners: Dict[str, List[Callable]] = {}

    def subscribe(self, event_type: str, listener: Callable):
        self._listeners.setdefault(event_type, []).append(listener)

    def publish(self, event_type: str, data: Any = None):
        for listener in self._listeners.get(event_type, []):
            listener(data)

class WidgetFactory(ABC):
    @abstractmethod
    def create_button(self, label: str, on_click: Callable) -> Any: pass

    @abstractmethod
    def create_label(self, text: str) -> Any: pass

class UIRenderer:
    def __init__(self, factory: WidgetFactory, event_bus: EventBus):
        self.factory = factory
        self.event_bus = event_bus
        self.widgets = []

    def add_button(self, label: str, event_type: str):
        def handler():
            self.event_bus.publish(event_type)
        self.widgets.append(self.factory.create_button(label, handler))

    def add_label(self, text: str):
        self.widgets.append(self.factory.create_label(text))

class QtFactory(WidgetFactory):
    def create_button(self, label: str, on_click: Callable) -> Any:
        from PyQt5.QtWidgets import QPushButton
        btn = QPushButton(label)
        btn.clicked.connect(on_click)
        return btn

    def create_label(self, text: str) -> Any:
        from PyQt5.QtWidgets import QLabel
        return QLabel(text)

class WxFactory(WidgetFactory):
    def create_button(self, label: str, on_click: Callable) -> Any:
        import wx
        btn = wx.Button(parent=None, label=label)
        btn.Bind(wx.EVT_BUTTON, lambda e: on_click())
        return btn

    def create_label(self, text: str) -> Any:
        import wx
        return wx.StaticText(parent=None, label=text)

class TextualFactory(WidgetFactory):
    def create_button(self, label: str, on_click: Callable) -> Any:
        from textual.widgets import Button
        return Button(label=label, on_click=on_click)

    def create_label(self, text: str) -> Any:
        from textual.widgets import Static
        return Static(text)

class BackendService:
    def __init__(self, event_bus: EventBus):
        event_bus.subscribe("button_click", self.handle_event)

    def handle_event(self, data: Any):
        print(f"Backend handling event with data: {data}")

# Platform-specific initialization example
if __name__ == "__main__":
