import redis
from functools import wraps
import time
from redis.exceptions import ConnectionError, TimeoutError
from redis.connection import ConnectionPool

class CircuitBreaker:
    def __init__(self, threshold=5, reset_timeout=30):
        self.threshold = threshold
        self.reset_timeout = reset_timeout
        self.failure_count = 0
        self.last_failure_time = 0
        self.is_open = False

    def check_state(self):
        if self.is_open:
            if time.time() > self.last_failure_time + self.reset_timeout:
                self.is_open = False
                self.failure_count = 0
                return False
            return True
        return False

    def record_failure(self):
        self.failure_count +=1
        if self.failure_count >= self.threshold:
            self.is_open = True
            self.last_failure_time = time.time()

class RedisCache:
    def __init__(self, host='localhost', port=6379, max_connections=100):
        self.pool = ConnectionPool(host=host, port=port, max_connections=max_connections)
        self.client = redis.Redis(connection_pool=self.pool)
        self.circuit_breaker = CircuitBreaker()

    def get(self, key):
        if self.circuit_breaker.check_state():
            return None
        try:
            return self.client.get(key)
        except (ConnectionError, TimeoutError):
            self.circuit_breaker.record_failure()
            return None

    def set(self, key, value, ttl):
        if self.circuit_breaker.check_state():
            return
        try:
            self.client.setex(key, ttl, value)
        except (ConnectionError, TimeoutError):
            self.circuit_breaker.record_failure()

    def bulk_set(self, items):
        if self.circuit_breaker.check_state():
            return
        try:
            with self.client.pipeline() as pipe:
                for key, value, ttl in items:
                    pipe.setex(key, ttl, value)
                pipe.execute()
        except (ConnectionError, TimeoutError):
            self.circuit_breaker.record_failure()

def distributed_memoize(ttl=60, redis_host='localhost', redis_port=6379):
    cache = RedisCache(redis_host, redis_port)

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f"{func.__name__}:{args}:{kwargs}"

            cached = cache.get(key)
            if cached is not None:
                return cached

            result = func(*args, **kwargs)

            cache.set(key, result, ttl)
            return result

        return wrapper
    return decorator
