from abc import ABC, abstractmethod
from typing import Optional, Dict, Any
import pytest

class Handler(ABC):
    _next_handler: Optional['Handler'] = None

    def set_next(self, handler: 'Handler') -> 'Handler':
        self._next_handler = handler
        return handler

    @abstractmethod
    def handle(self, data: Dict[str, Any]) -> Dict[str, Any]:
        if self._next_handler:
            return self._next_handler.handle(data)
        return data

class DataLoader(Handler):
    def handle(self, data: Dict[str, Any]) -> Dict[str, Any]:
        # Load data implementation
        return super().handle({**data, 'loaded': True})

class DataCleaner(Handler):
    def handle(self, data: Dict[str, Any]) -> Dict[str, Any]:
        # Data cleaning implementation
        return super().handle({**data, 'cleaned': True})

class DataTransformer(Handler):
    def handle(self, data: Dict[str, Any]) -> Dict[str, Any]:
        # Data transformation implementation
        return super().handle({**data, 'transformed': True})

# Test implementations
class TestHandler:
    @pytest.fixture
    def pipeline(self):
        loader = DataLoader()
        cleaner = DataCleaner()
        transformer = DataTransformer()
        loader.set_next(cleaner).set_next(transformer)
        return loader

    def test_loader_contract(self):
        assert DataLoader().handle({}) == {'loaded': True, 'cleaned': True, 'transformed': True}

    def test_cleaner_contract(self):
        cleaner = DataCleaner()
        cleaner.set_next(DataTransformer())
        assert cleaner.handle({'loaded': True}) == {'loaded': True, 'cleaned': True, 'transformed': True}

    def test_full_pipeline(self, pipeline):
        assert pipeline.handle({}) == {'loaded': True, 'cleaned': True, 'transformed': True}
