const express = require('express');
const crypto = require('crypto');
const mongoose = require('mongoose');
const AWS = require('aws-sdk');
const fs = require('fs');
const path = require('path');

mongoose.connect('mongodb://localhost/uploads');
const UploadSession = mongoose.model('UploadSession', new mongoose.Schema({
  uploadId: { type: String, unique: true },
  fileName: String,
  totalChunks: Number,
  chunkSize: Number,
  uploadedChunks: [Number],
  idempotencyToken: String,
  status: { type: String, default: 'pending' },
  checksum: String,
  s3UploadId: String,
  parts: [Object]
}));

const app = express();
app.use(express.json({ limit: '50mb' }));

const s3 = process.env.AWS_ACCESS_KEY_ID ? new AWS.S3() : null;
const TEMP_DIR = './tmp';

app.post('/start-upload', async (req, res) => {
  const { fileName, totalChunks, chunkSize, checksum } = req.body;
  const uploadId = crypto.randomUUID();
  const idempotencyToken = crypto.randomUUID();

  await UploadSession.create({
    uploadId,
    fileName,
    totalChunks,
    chunkSize,
    idempotencyToken,
    checksum
  });

  res.json({ uploadId, idempotencyToken });
});

app.put('/upload/:uploadId/:chunkIndex', async (req, res) => {
  const { uploadId, chunkIndex } = req.params;
  const { chunk, idempotencyToken, chunkChecksum } = req.body;

  const session = await UploadSession.findOne({ uploadId });
  if (session.idempotencyToken !== idempotencyToken) return res.sendStatus(409);

  const calculatedChecksum = crypto.createHash('md5').update(chunk).digest('hex');
  if (calculatedChecksum !== chunkChecksum) return res.sendStatus(400);

  if (s3) {
    const partParams = {
      Bucket: process.env.S3_BUCKET,
      Key: uploadId,
      PartNumber: parseInt(chunkIndex) + 1,
      Body: chunk,
      UploadId: session.s3UploadId
    };
    const uploadPart = await s3.uploadPart(partParams).promise();
    session.parts.push({ ETag: uploadPart.ETag, PartNumber: partParams.PartNumber });
  } else {
    const chunkPath = path.join(TEMP_DIR, `${uploadId}_${chunkIndex}`);
    fs.writeFileSync(chunkPath, chunk);
  }

  session.uploadedChunks.push(parseInt(chunkIndex));
  await session.save();
  res.sendStatus(200);
});

app.post('/complete-upload/:uploadId', async (req, res) => {
  const { uploadId } = req.params;
  const session = await UploadSession.findOne({ uploadId });

  if (session.uploadedChunks.length !== session.totalChunks) return res.sendStatus(400);

  if (s3) {
    await s3.completeMultipartUpload({
      Bucket: process.env.S3_BUCKET,
      Key: session.fileName,
      UploadId: session.s3UploadId,
      MultipartUpload: { Parts: session.parts }
    }).promise();
  } else {
    const finalPath = path.join(__dirname, 'uploads', session.fileName);
    const writeStream = fs.createWriteStream(finalPath);
    for (let i = 0; i < session.totalChunks; i++) {
      const chunkPath = path.join(TEMP_DIR, `${uploadId}_${i}`);
      writeStream.write(fs.readFileSync(chunkPath));
      fs.unlinkSync(chunkPath);
    }
    writeStream.end();
  }

  session.status = 'completed';
  await session.save();
  res.sendStatus(200);
});

app.get('/upload-status/:uploadId', async (req, res) => {
  const session = await UploadSession.findOne({ uploadId: req.params.uploadId });
  res.json({ uploadedChunks: session.uploadedChunks });
});

app.listen(3000);
