import abc
from dataclasses import dataclass
from typing import Optional, Dict, Tuple
import requests

@dataclass
class Coordinates:
    lat: float
    lng: float

class GeocodingService(abc.ABC):
    @abc.abstractmethod
    def get_coordinates(self, address: str) -> Optional[Coordinates]:
        pass

    @abc.abstractmethod
    def get_address(self, coords: Coordinates) -> Optional[str]:
        pass

class GoogleMapsGeocoder(GeocodingService):
    def __init__(self, api_key: str):
        self.base_url = "https://maps.googleapis.com/maps/api/geocode/json"
        self.api_key = api_key

    def get_coordinates(self, address: str) -> Optional[Coordinates]:
        response = requests.get(
            self.base_url,
            params={"address": address, "key": self.api_key}
        )
        data = response.json()
        if results := data.get("results"):
            location = results[0]["geometry"]["location"]
            return Coordinates(location["lat"], location["lng"])
        return None

    def get_address(self, coords: Coordinates) -> Optional[str]:
        response = requests.get(
            self.base_url,
            params={"latlng": f"{coords.lat},{coords.lng}", "key": self.api_key}
        )
        data = response.json()
        return data.get("results", [{}])[0].get("formatted_address")

class MapboxGeocoder(GeocodingService):
    def __init__(self, access_token: str):
        self.base_url = "https://api.mapbox.com/geocoding/v5/mapbox.places"
        self.access_token = access_token

    def get_coordinates(self, address: str) -> Optional[Coordinates]:
        response = requests.get(
            f"{self.base_url}/{address}.json",
            params={"access_token": self.access_token}
        )
        data = response.json()
        if features := data.get("features"):
            coords = features[0]["center"]
            return Coordinates(coords[1], coords[0])
        return None

    def get_address(self, coords: Coordinates) -> Optional[str]:
        response = requests.get(
            f"{self.base_url}/{coords.lng},{coords.lat}.json",
            params={"access_token": self.access_token}
        )
        data = response.json()
        return data.get("features", [{}])[0].get("place_name")

class CachedGeocodingService(GeocodingService):
    def __init__(self, geocoder: GeocodingService):
        self.geocoder = geocoder
        self.address_cache: Dict[str, Coordinates] = {}
        self.coords_cache: Dict[Tuple[float, float], str] = {}

    def get_coordinates(self, address: str) -> Optional[Coordinates]:
        if address not in self.address_cache:
            self.address_cache[address] = self.geocoder.get_coordinates(address)
        return self.address_cache[address]

    def get_address(self, coords: Coordinates) -> Optional[str]:
        key = (coords.lat, coords.lng)
        if key not in self.coords_cache:
            self.coords_cache[key] = self.geocoder.get_address(coords)
        return self.coords_cache[key]


