const WebSocket = require('ws');
const Redis = require('ioredis');
const ConsistentHashing = require('hash-ring');

const redisNodes = [{ port: 6379, host: 'localhost' }];
const serverId = process.env.SERVER_ID || 'node1';
const port = process.env.PORT || 8080;

class WebSocketShard {
  constructor() {
    this.connections = new Map();
    this.ring = new ConsistentHashing({ nodes: [serverId] });

    this.redis = new Redis(redisNodes);
    this.pubSub = new Redis(redisNodes);

    this.pubSub.subscribe('node-events', 'cross-node-messages');
    this.pubSub.on('message', (channel, message) => {
      if (channel === 'node-events') this.handleNodeEvent(message);
      if (channel === 'cross-node-messages') this.handleCrossNodeMessage(message);
    });

    this.wss = new WebSocket.Server({ port });
    this.setupWebSocketHandlers();

    this.redis.publish('node-events', JSON.stringify({ type: 'join', node: serverId }));
  }

  setupWebSocketHandlers() {
    this.wss.on('connection', (ws, req) => {
      const clientId = new URL(req.url, `http://${req.headers.host}`).searchParams.get('clientId');
      if (!clientId || this.ring.getNode(clientId) !== serverId) return ws.close();

      this.connections.set(clientId, ws);
      ws.on('message', (data) => this.routeMessage(clientId, data.toString()));
      ws.on('close', () => this.connections.delete(clientId));
    });
  }

  routeMessage(senderId, message) {
    const [targetId, ...content] = message.split(':');
    const targetNode = this.ring.getNode(targetId);

    if (targetNode === serverId) {
      const targetConn = this.connections.get(targetId);
      targetConn?.send(`${senderId}:${content.join(':')}`);
    } else {
      this.redis.publish('cross-node-messages', 
        JSON.stringify({ targetId, message: `${senderId}:${content.join(':')}` }));
    }
  }

  handleCrossNodeMessage(message) {
    const { targetId, message: msg } = JSON.parse(message);
    const targetConn = this.connections.get(targetId);
    targetConn?.send(msg);
  }

  handleNodeEvent(event) {
    const { type, node } = JSON.parse(event);
    type === 'join' ? this.ring.addNode(node) : this.ring.removeNode(node);
  }
}

process.on('SIGINT', () => {
  new Redis(redisNodes).publish('node-events', JSON.stringify({ type: 'leave', node: serverId }));
  process.exit();
});

new WebSocketShard();
