import click
import sqlparse
from pathlib import Path
from rich.console import Console
from rich.syntax import Syntax
from rich.table import Table
from pygments.lexers.sql import SqlLexer
import sqlite3
from collections import deque

console = Console()
MIGRATIONS_DIR = Path("migrations")
UNDO_STACK = deque()
DB_CONN = sqlite3.connect(":memory:")

class Migration:
    def __init__(self, name):
        self.name = name
        self.up = Path(MIGRATIONS_DIR / f"{name}_up.sql").read_text()
        self.down = Path(MIGRATIONS_DIR / f"{name}_down.sql").read_text()

def validate_query(query):
    try:
        sqlparse.parse(query)
        DB_CONN.cursor().execute(f"EXPLAIN {query}")
        return True
    except:
        return False

@click.group()
def cli():
    pass

def get_migrations():
    return [f.stem.replace("_up", "") for f in MIGRATIONS_DIR.glob("*_up.sql")]

@cli.command()
@click.option("--dry-run", is_flag=True)
@click.argument("name", autocompletion=get_migrations)
def migrate(name, dry_run):
    migration = Migration(name)

    console.print(f"\n[bold]Previewing migration [green]{name}[/]:[/]")
    console.print(Syntax(migration.up, "sql", lexer=SqlLexer()))

    if not validate_query(migration.up):
        console.print("[red]✘ Invalid SQL syntax[/]")
        return

    if dry_run:
        console.print(f"[yellow]✔ Dry run complete for {name}[/]")
        return

    UNDO_STACK.append(migration)
    DB_CONN.executescript(migration.up)

    table = Table(title="Migration Progress")
    table.add_column("Migration", style="cyan")
    table.add_column("Status", style="magenta")
    table.add_row(name, "✔ Applied")
    console.print(table)

@cli.command()
def undo():
    if not UNDO_STACK:
        console.print("[red]Nothing to undo[/]")
        return

    migration = UNDO_STACK.pop()
    DB_CONN.executescript(migration.down)
    console.print(f"[green]✔ Reverted {migration.name}[/]")

@cli.command()
def history():
    table = Table(title="Migration History")
    table.add_column("ID", style="cyan")
    table.add_column("Name", style="magenta")

    for idx, migration in enumerate(UNDO_STACK):
        table.add_row(str(idx+1), migration.name)

    console.print(table)

if __name__ == "__main__":
    cli()
