  const codeVerifier = crypto.randomBytes(32).toString('base64url');
  const codeChallenge = createHash('sha256').update(codeVerifier).digest('base64url');

  codeVerifiers.set(req.query.state, codeVerifier);

  res.cookie('csrfToken', csrfToken, {
    httpOnly: true,
    secure: true,
    sameSite: 'Strict',
    signed: true,
  });

  res.redirect(`${process.env.AUTH_SERVER}/auth?${new URLSearchParams({
    client_id: process.env.CLIENT_ID,
    redirect_uri: process.env.REDIRECT_URI,
    response_type: 'code',
    code_challenge: codeChallenge,
    code_challenge_method: 'S256',
    state: req.query.state,
  })}`);
});

app.post('/token', (req, res) => {
  const { code, state } = req.body;
  const codeVerifier = codeVerifiers.get(state);

  if (!codeVerifier) return res.sendStatus(400);

  const accessToken = crypto.randomBytes(32).toString('hex');
  const refreshToken = crypto.randomBytes(32).toString('hex');

  refreshTokens.set(refreshToken, { accessToken, expires: Date.now() + 3600000 });
  codeVerifiers.delete(state);

  res.json({
    access_token: accessToken,
    refresh_token: refreshToken,
    expires_in: 3600,
    token_type: 'Bearer'
  });
});

app.post('/refresh', (req, res) => {
  const oldRefreshToken = req.body.refresh_token;
  const stored = refreshTokens.get(oldRefreshToken);

  if (!stored) return res.sendStatus(401);

  const newAccessToken = crypto.randomBytes(32).toString('hex');
  const newRefreshToken = crypto.randomBytes(32).toString('hex');

  refreshTokens.delete(oldRefreshToken);
  refreshTokens.set(newRefreshToken, { 
    accessToken: newAccessToken,
    expires: Date.now() + 3600000
  });

  res.json({
    access_token: newAccessToken,
    refresh_token: newRefreshToken,
    expires_in: 3600,
    token_type: 'Bearer'
  });
});

app.listen(3000);
