// SPA (Client-side)
async function beginAuthFlow() {
  const state = crypto.getRandomValues(new Uint8Array(16)).join('');
  const codeVerifier = generateRandomString(64);
  const codeChallenge = await generateCodeChallenge(codeVerifier);

  sessionStorage.setItem(state, codeVerifier);

  const authUrl = new URL(`${SERVER_URL}/authorize`);
  authUrl.searchParams.append('state', state);
  authUrl.searchParams.append('client_id', CLIENT_ID);
  window.location.href = authUrl;
}

async function handleAuthCallback() {
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const state = params.get('state');

  const codeVerifier = sessionStorage.getItem(state);
  sessionStorage.removeItem(state);

  const response = await fetch(`${SERVER_URL}/token`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-CSRF-Token': getCSRFTokenFromCookie(),
    },
    body: JSON.stringify({ code, state, code_verifier: codeVerifier }),
  });

  const tokens = await response.json();
  storeTokens(tokens);
}

function generateRandomString(length) {
  return crypto.getRandomValues(new Uint8Array(length))
    .reduce((str, byte) => str + byte.toString(16).padStart(2, '0'), '');
}

async function generateCodeChallenge(verifier) {
  const digest = await crypto.subtle.digest('SHA-256', 
    new TextEncoder().encode(verifier));
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function getCSRFTokenFromCookie() {
  return document.cookie
    .split('; ')
    .find(row => row.startsWith('csrfToken='))
    ?.split('=')[1];
}
