using System;
using System.Text;
using System.Collections.Generic;

public interface ISpecification<T>
{
    bool IsSatisfiedBy(T candidate);
    string ToDotGraph();
}

public abstract class Specification<T> : ISpecification<T>
{
    public abstract bool IsSatisfiedBy(T candidate);

    public Specification<T> And(Specification<T> other) => new AndSpecification<T>(this, other);
    public Specification<T> Or(Specification<T> other) => new OrSpecification<T>(this, other);
    public Specification<T> Not() => new NotSpecification<T>(this);

    public abstract string ToDotGraph();
}

public class AndSpecification<T> : Specification<T>
{
    private readonly Specification<T> _left;
    private readonly Specification<T> _right;

    public AndSpecification(Specification<T> left, Specification<T> right)
    {
        _left = left;
        _right = right;
    }

    public override bool IsSatisfiedBy(T candidate) => 
        _left.IsSatisfiedBy(candidate) && _right.IsSatisfiedBy(candidate);

    public override string ToDotGraph()
    {
        var sb = new StringBuilder();
        sb.AppendLine($"node{this.GetHashCode()} [label=\"AND\"];");
        sb.AppendLine($"node{this.GetHashCode()} -> node{_left.GetHashCode()};");
        sb.AppendLine($"node{this.GetHashCode()} -> node{_right.GetHashCode()};");
        sb.Append(_left.ToDotGraph());
        sb.Append(_right.ToDotGraph());
        return sb.ToString();
    }
}

public class OrSpecification<T> : Specification<T>
{
    private readonly Specification<T> _left;
    private readonly Specification<T> _right;

    public OrSpecification(Specification<T> left, Specification<T> right)
    {
        _left = left;
        _right = right;
    }

    public override bool IsSatisfiedBy(T candidate) => 
        _left.IsSatisfiedBy(candidate) || _right.IsSatisfiedBy(candidate);

    public override string ToDotGraph()
    {
        var sb = new StringBuilder();
        sb.AppendLine($"node{this.GetHashCode()} [label=\"OR\"];");
        sb.AppendLine($"node{this.GetHashCode()} -> node{_left.GetHashCode()};");
        sb.AppendLine($"node{this.GetHashCode()} -> node{_right.GetHashCode()};");
        sb.Append(_left.ToDotGraph());
        sb.Append(_right.ToDotGraph());
        return sb.ToString();
    }
}

public class NotSpecification<T> : Specification<T>
{
    private readonly Specification<T> _spec;

    public NotSpecification(Specification<T> spec) => _spec = spec;

    public override bool IsSatisfiedBy(T candidate) => !_spec.IsSatisfiedBy(candidate);

    public override string ToDotGraph()
    {
        var sb = new StringBuilder();
        sb.AppendLine($"node{this.GetHashCode()} [label=\"NOT\"];");
        sb.AppendLine($"node{this.GetHashCode()} -> node{_spec.GetHashCode()};");
        sb.Append(_spec.ToDotGraph());
        return sb.ToString();
    }
}

// Example rule implementations
public class IsPremiumCustomer : Specification<Customer>
{
    public override bool IsSatisfiedBy(Customer customer) => customer.IsPremium;

    public override string ToDotGraph() => 
        $"node{this.GetHashCode()} [label=\"IsPremiumCustomer\"];\n";
}

public class HasOrderOver100 : Specification<Customer>
{
    public override bool IsSatisfiedBy(Customer customer) => customer.OrderTotal > 100;

    public override string ToDotGraph() => 
        $"node{this.GetHashCode()} [label=\"HasOrderOver100\"];\n";
}

// Example domain object
public class Customer
{
    public bool IsPremium { get; set; }
    public decimal OrderTotal { get; set; }
}

// Usage example
public class Program
{
    public static void Main()
    {
        var spec = new IsPremiumCustomer().And(new HasOrderOver100());
        var dotGraph = $"digraph {{\n{spec.ToDotGraph()}}}";
        Console.WriteLine(dotGraph);

        var customer = new Customer { IsPremium = true, OrderTotal = 200 };
        Console.WriteLine(spec.IsSatisfiedBy(customer)); // True
    }
}
