package main

import (
	"bufio"
	"compress/gzip"
	"io"
	"os"
	"regexp"
	"runtime"
	"strings"
	"sync"
	"testing"
)

var logRegex = regexp.MustCompile(`^(\S+) (\S+) (\S+) \[([^\]]+)\] "(\S+) (\S+) (\S+)" (\d+) (\d+)$`)

type LogEntry struct {
	Method, Path, Protocol string
	Status                 int
}

var bufPool = sync.Pool{
	New: func() interface{} { return make([]byte, 0, 4096) },
}

func parseLog(r io.Reader) {
	lines := make(chan string, 1024)
	var wg sync.WaitGroup

	for i := 0; i < runtime.NumCPU(); i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for line := range lines {
				matches := logRegex.FindStringSubmatch(line)
				if len(matches) < 9 {
					continue
				}
				_ = LogEntry{
					Method:   matches[5],
					Path:     matches[6],
					Protocol: matches[7],
				}
			}
		}()
	}

	gr, _ := gzip.NewReader(r)
	defer gr.Close()
	scanner := bufio.NewScanner(gr)

	for scanner.Scan() {
		lines <- scanner.Text()
	}
	close(lines)
	wg.Wait()
}

func BenchmarkParser(b *testing.B) {
	sizes := []int{1e3, 1e4, 1e5, 1e6}
	cores := []int{1, 2, 4, 8}

	for _, size := range sizes {
		data := generateData(size)
		compressed := compressData(data)
		b.Run("size="+humanize(size), func(b *testing.B) {
			for _, core := range cores {
				runtime.GOMAXPROCS(core)
				b.Run(humanize(core), func(b *testing.B) {
					b.SetBytes(int64(len(data)))
					for i := 0; i < b.N; i++ {
						parseLog(compressed)
					}
				})
			}
		})
	}
}

func generateData(lines int) string {
	var sb strings.Builder
	for i := 0; i < lines; i++ {
		sb.WriteString(`127.0.0.1 - - [10/Oct/2000:13:55:36 -0700] "GET /test HTTP/1.1" 200 1024` + "\n")
	}
	return sb.String()
}

func compressData(data string) *strings.Reader {
	var buf strings.Builder
	gw := gzip.NewWriter(&buf)
	gw.Write([]byte(data))
	gw.Close()
	return strings.NewReader(buf.String())
}

func humanize(n int) string {
	return strings.ReplaceAll(strings.ToLower(byteCountSI(n)), " ", "")
}

func byteCountSI(b int) string {
	const unit = 1000
	if b < unit {
		return string(rune(b))
	}
	div, exp := unit, 0
	for n := b / unit; n >= unit; n /= unit {
		div *= unit
		exp++
	}
	return string(rune(b/div)) + "kMGTPE"[exp:exp+1]
}
