const express = require('express');
const jwt = require('jsonwebtoken');
const cors = require('cors');
const helmet = require('helmet');
const { v4: uuidv4 } = require('uuid');
const bodyParser = require('body-parser');
const cookieParser = require('cookie-parser');
const Redis = require('ioredis');

const app = express();
const redis = new Redis();

// Config
const JWT_SECRET_CURRENT = process.env.JWT_SECRET_CURRENT || 'current_secret';
const JWT_SECRET_PREVIOUS = process.env.JWT_SECRET_PREVIOUS || 'previous_secret';
const ACCESS_TOKEN_EXPIRY = '15m';
const REFRESH_TOKEN_EXPIRY = '7d';
const CSRF_WHITELIST = new Set(['https://yourdomain.com']);

// Middleware
app.use(helmet());
app.use(cors({ origin: Array.from(CSRF_WHITELIST), credentials: true }));
app.use(bodyParser.json());
app.use(cookieParser());

// Token generation utilities
const generateAccessToken = (userId) => {
  return jwt.sign(
    { jti: uuidv4(), userId },
    JWT_SECRET_CURRENT,
    { expiresIn: ACCESS_TOKEN_EXPIRY }
  );
};

const generateRefreshToken = (userId) => {
  return jwt.sign(
    { jti: uuidv4(), userId, type: 'refresh' },
    JWT_SECRET_CURRENT,
    { expiresIn: REFRESH_TOKEN_EXPIRY }
  );
};

// Security middleware
const csrfProtection = (req, res, next) => {
  const origin = req.get('origin');
  const referer = req.get('referer');

  if (!CSRF_WHITELIST.has(origin) && !CSRF_WHITELIST.has(referer)) {
    return res.status(403).send('CSRF validation failed');
  }
  next();
};

const checkTokenValidity = async (token) => {
  return !(await redis.exists(`invalidated:${token.jti}`));
};

const authenticateToken = async (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.sendStatus(401);

  try {
    let payload = jwt.verify(token, JWT_SECRET_CURRENT, { ignoreExpiration: true });
    if (!payload.jti || !(await checkTokenValidity(payload))) return res.sendStatus(403);

    req.user = payload;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      try {
        const payload = jwt.verify(token, JWT_SECRET_PREVIOUS, { ignoreExpiration: true });
        if (!payload.jti || !(await checkTokenValidity(payload))) return res.sendStatus(403);
        req.user = payload;
        next();
      } catch (err) {
        return res.sendStatus(403);
      }
    } else {
      return res.sendStatus(403);
    }
  }
};

// Routes
app.post('/login', csrfProtection, async (req, res) => {
  // Validate credentials here
  const userId = 'user123';
  const accessToken = generateAccessToken(userId);
  const refreshToken = generateRefreshToken(userId);

  await redis.set(`refresh:${refreshToken}`, userId, 'EX', 7 * 86400);
  res.cookie('refreshToken', refreshToken, { httpOnly: true, secure: true, sameSite: 'Strict' });
  res.json({ accessToken });
});

app.post('/refresh', csrfProtection, async (req, res) => {
  const refreshToken = req.cookies.refreshToken || req.body.refreshToken;
  if (!refreshToken) return res.sendStatus(401);

  try {
    const payload = jwt.verify(refreshToken, JWT_SECRET_CURRENT);
    if (payload.type !== 'refresh') return res.sendStatus(403);

    const userId = await redis.get(`refresh:${refreshToken}`);
    if (!userId || userId !== payload.userId) return res.sendStatus(403);

    await redis.del(`refresh:${refreshToken}`);
    const newAccessToken = generateAccessToken(userId);
    const newRefreshToken = generateRefreshToken(userId);

    await redis.set(`refresh:${newRefreshToken}`, userId, 'EX', 7 * 86400);
    res.cookie('refreshToken', newRefreshToken, { httpOnly: true, secure: true, sameSite: 'Strict' });
    res.json({ accessToken: newAccessToken });
  } catch (err) {
    res.sendStatus(403);
  }
});

app.post('/logout', authenticateToken, async (req, res) => {
  await redis.set(`invalidated:${req.user.jti}`, '1', 'EX', 60 * 15);
  res.sendStatus(204);
});

// Protected route example
app.get('/protected', authenticateToken, csrfProtection, (req, res) => {
  res.json({ message: 'Secure data' });
});

app.listen(3000, () => console.log('Server running on port 3000'));
