use actix_web::{
    middleware::Logger,
    web::{self, Bytes},
    App, Error, HttpResponse, HttpServer,
};
use env_logger::Env;
use rusqlite::{params, Connection, OptionalExtension};
use std::{
    fs::{self, File, OpenOptions},
    io::Write,
    path::PathBuf,
    sync::Mutex,
};
use uuid::Uuid;

struct AppState {
    db: Mutex<Connection>,
    upload_dir: PathBuf,
}

#[derive(Debug)]
struct Upload {
    id: String,
    file_name: String,
    total_chunks: usize,
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::Builder::from_env(Env::default().default_filter_or("info")).init();

    let upload_dir = PathBuf::from("./uploads");
    fs::create_dir_all(&upload_dir)?;

    let db = Connection::open("uploads.db").expect("Failed to open DB");
    db.execute_batch(
        "CREATE TABLE IF NOT EXISTS uploads (
            id TEXT PRIMARY KEY,
            file_name TEXT NOT NULL,
            total_chunks INTEGER NOT NULL,
            created_at DATETIME DEFAULT CURRENT_TIMESTAMP
        );
        CREATE TABLE IF NOT EXISTS chunks (
            upload_id TEXT NOT NULL,
            chunk_number INTEGER NOT NULL,
            path TEXT NOT NULL,
            uploaded_at DATETIME DEFAULT CURRENT_TIMESTAMP,
            PRIMARY KEY (upload_id, chunk_number),
            FOREIGN KEY(upload_id) REFERENCES uploads(id)
        );",
    )
    .expect("Failed to create tables");

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(AppState {
                db: Mutex::new(db.try_clone().unwrap()),
                upload_dir: upload_dir.clone(),
            }))
            .wrap(Logger::default())
            .service(
                web::resource("/upload/start")
                    .route(web::post().to(start_upload)),
            )
            .service(
                web::resource("/upload/{upload_id}/{chunk_num}")
                    .route(web::post().to(upload_chunk)),
            )
            .service(
                web::resource("/upload/{upload_id}/complete")
                    .route(web::post().to(complete_upload)),
            )
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

async fn start_upload(
    state: web::Data<AppState>,
    params: web::Json<(String, usize)>,
) -> Result<HttpResponse, Error> {
    let (file_name, total_chunks) = params.into_inner();
    let upload_id = Uuid::new_v4().to_string();

    state.db.lock().unwrap().execute(
        "INSERT INTO uploads (id, file_name, total_chunks) VALUES (?1, ?2, ?3)",
        params![upload_id, file_name, total_chunks],
    )?;

    Ok(HttpResponse::Ok().json(upload_id))
}

async fn upload_chunk(
    state: web::Data<AppState>,
    path: web::Path<(String, usize)>,
    payload: Bytes,
) -> Result<HttpResponse, Error> {
    let (upload_id, chunk_num) = path.into_inner();
    let chunk_path = state.upload_dir.join(format!("{}-{}", upload_id, chunk_num));

    // Check if chunk already exists
    let exists: Option<i32> = state.db.lock().unwrap()
        .query_row(
            "SELECT 1 FROM chunks WHERE upload_id = ?1 AND chunk_number = ?2",
            params![upload_id, chunk_num],
            |row| row.get(0),
        )
        .optional()?;

    if exists.is_some() {
        return Ok(HttpResponse::Ok().finish());
    }

    // Write chunk with retry logic
    let mut attempts = 0;
    loop {
        match OpenOptions::new()
            .create_new(true)
            .write(true)
            .open(&chunk_path)
        {
            Ok(mut file) => {
                if let Err(e) = file.write_all(&payload) {
                    log::error!("Failed to write chunk {}: {:?}", chunk_num, e);
                    attempts += 1;
                    if attempts >= 3 {
                        return Ok(HttpResponse::InternalServerError().finish());
                    }
                    continue;
                }
                break;
            }
            Err(e) => {
                log::error!("Failed to create chunk {}: {:?}", chunk_num, e);
                return Ok(HttpResponse::InternalServerError().finish());
            }
        }
    }

    state.db.lock().unwrap().execute(
        "INSERT INTO chunks (upload_id, chunk_number, path) VALUES (?1, ?2, ?3)",
        params![upload_id, chunk_num, chunk_path.to_str()],
    )?;

    Ok(HttpResponse::Ok().finish())
}

async fn complete_upload(
    state: web::Data<AppState>,
    upload_id: web::Path<String>,
) -> Result<HttpResponse, Error> {
    let upload_id = upload_id.into_inner();
    let db = state.db.lock().unwrap();

    let upload: Upload = db.query_row(
        "SELECT id, file_name, total_chunks FROM uploads WHERE id = ?1",
        params![upload_id],
        |row| Ok(Upload { id: row.get(0)?, file_name: row.get(1)?, total_chunks: row.get(2)? }),
    )?;

    let mut final_path = state.upload_dir.join(&upload.file_name);
    let mut final_file = File::create(&final_path)?;

    for chunk_num in 0..upload.total_chunks {
        let chunk_path = state.upload_dir.join(format!("{}-{}", upload_id, chunk_num));
        let mut chunk_file = File::open(&chunk_path)?;
        std::io::copy(&mut chunk_file, &mut final_file)?;
        fs::remove_file(&chunk_path)?;
    }

    Ok(HttpResponse::Ok().finish())
