import React, { useState, useCallback } from 'react';

interface SchemaField {
  type: string;
  comment?: string;
  properties?: Record<string, SchemaField>;
}

interface HistoryState {
  schemas: SchemaField[];
  currentIndex: number;
}

const SchemaEditor: React.FC = () => {
  const [schema, setSchema] = useState<SchemaField>({
    type: 'object',
    properties: {}
  });
  const [history, setHistory] = useState<HistoryState>({
    schemas: [],
    currentIndex: -1
  });
  const [error, setError] = useState<string>('');

  const validateSchema = useCallback((currentSchema: SchemaField) => {
    if (!currentSchema.type) return 'Type is required';
    if (currentSchema.type === 'object' && !currentSchema.properties) return 'Object requires properties';
    return '';
  }, []);

  const updateSchema = useCallback((newSchema: SchemaField) => {
    const validationError = validateSchema(newSchema);
    setError(validationError);
    if (!validationError) {
      setHistory(prev => ({
        schemas: [...prev.schemas.slice(0, prev.currentIndex + 1), newSchema],
        currentIndex: prev.currentIndex + 1
      }));
      setSchema(newSchema);
    }
  }, [validateSchema]);

  const handleUndo = () => {
    setHistory(prev => prev.currentIndex > 0 ? 
      { ...prev, currentIndex: prev.currentIndex - 1 } : prev);
    setSchema(history.schemas[history.currentIndex - 1]);
  };

  const handleRedo = () => {
    setHistory(prev => prev.currentIndex < prev.schemas.length - 1 ? 
      { ...prev, currentIndex: prev.currentIndex + 1 } : prev);
    setSchema(history.schemas[history.currentIndex + 1]);
  };

  return (
    <div className="schema-editor">
      <div className="toolbar">
        <button onClick={handleUndo} disabled={history.currentIndex <= 0}>Undo</button>
        <button onClick={handleRedo} disabled={history.currentIndex >= history.schemas.length - 1}>Redo</button>
      </div>
      {error && <div className="error">{error}</div>}
      <FieldEditor
        field={schema}
        onChange={updateSchema}
        path="root"
        depth={0}
      />
    </div>
  );
};

const FieldEditor: React.FC<{
  field: SchemaField;
  onChange: (newField: SchemaField) => void;
  path: string;
  depth: number;
}> = ({ field, onChange, path, depth }) => {
  const [isExpanded, setIsExpanded] = useState(true);
  const [showTypeDropdown, setShowTypeDropdown] = useState(false);

  const handleAddProperty = () => {
    const newProperties = {
      ...field.properties,
      ['newField']: { type: 'string' }
    };
    onChange({ ...field, properties: newProperties });
  };

  return (
    <div className="field" style={{ marginLeft: depth * 20 }}>
      <div className="field-header">
        <span onClick={() => setIsExpanded(!isExpanded)}>
          {isExpanded ? '▼' : '▶'} {path}
        </span>
        <div className="type-selector">
          <input
            value={field.type}
            onClick={() => setShowTypeDropdown(!showTypeDropdown)}
            readOnly
          />
          {showTypeDropdown && (
            <div className="type-dropdown">
              {['string', 'number', 'boolean', 'object', 'array'].map(t => (
                <div key={t} onClick={() => onChange({ ...field, type: t })}>{t}</div>
              ))}
            </div>
          )}
        </div>
        {field.comment && <span className="tooltip">ℹ️<div className="tooltiptext">{field.comment}</div></span>}
      </div>
      {isExpanded && field.properties && (
        <div className="properties">
          {Object.entries(field.properties).map(([key, value]) => (
            <FieldEditor
              key={key}
              field={value}
              onChange={(newValue) => {
                const newProperties = { ...field.properties, [key]: newValue };
                onChange({ ...field, properties: newProperties });
              }}
              path={key}
              depth={depth + 1}
            />
          ))}
          <button onClick={handleAddProperty}>+ Add Field</button>
        </div>
      )}
    </div>
  );
};

export default SchemaEditor;
