package main

import (
    "crypto/sha256"
    "encoding/base64"
    "encoding/json"
    "fmt"
    "net/http"
    "sync"
    "time"

    "github.com/gorilla/mux"
    "golang.org/x/crypto/bcrypt"
    "golang.org/x/time/rate"
)

var (
    authCodes   = make(map[string]authCode)
    tokens      = make(map[string]bool)
    states      = make(map[string]bool)
    clients     = map[string]string{"test_client": "test_secret"}
    mutex       = sync.RWMutex{}
    codeVerifier string
)

type authCode struct {
    Code        string
    CodeVerifier string
    ClientID    string
    RedirectURI string
    Expires    time.Time
}

func main() {
    r := mux.NewRouter()

    r.Use(auditLog)
    r.Use(enforceTLS)

    r.Handle("/auth", rateLimit(100)(http.HandlerFunc(authHandler))).Methods("GET")
    r.Handle("/token", rateLimit(100)(http.HandlerFunc(tokenHandler))).Methods("POST")
    r.Handle("/revoke", rateLimit(100)(http.HandlerFunc(revokeHandler))).Methods("POST")

    http.ListenAndServeTLS(":443", "cert.pem", "key.pem", r)
}

func authHandler(w http.ResponseWriter, r *http.Request) {
    clientID := r.URL.Query().Get("client_id")
    redirectURI := r.URL.Query().Get("redirect_uri")

    state := generateRandomString(32)
    codeVerifier = generateRandomString(64)
    codeChallenge := generatePKCECodeChallenge(codeVerifier)

    mutex.Lock()
    authCodes[state] = authCode{
        Code:        generateRandomString(32),
        CodeVerifier: codeVerifier,
        ClientID:    clientID,
        RedirectURI: redirectURI,
        Expires:     time.Now().Add(10 * time.Minute),
    }
    states[state] = true
    mutex.Unlock()

    http.Redirect(w, r, fmt.Sprintf("%s?code=%s&state=%s", redirectURI, authCodes[state].Code, state), http.StatusFound)
}

func tokenHandler(w http.ResponseWriter, r *http.Request) {
    r.ParseForm()
    code := r.FormValue("code")
    state := r.FormValue("state")
    verifier := r.FormValue("code_verifier")

    mutex.RLock()
    storedCode, validCode := authCodes[state]
    _, validState := states[state]
    mutex.RUnlock()

    if !validCode || !validState || storedCode.Code != code {
        http.Error(w, "invalid request", http.StatusBadRequest)
        return
    }

    if storedCode.Expires.Before(time.Now()) {
        http.Error(w, "code expired", http.StatusBadRequest)
        return
    }

    if generatePKCECodeChallenge(verifier) != generatePKCECodeChallenge(storedCode.CodeVerifier) {
        http.Error(w, "invalid code verifier", http.StatusBadRequest)
        return
    }

    accessToken := generateRandomString(32)
    refreshToken := generateRandomString(32)

    mutex.Lock()
    tokens[accessToken] = true
    tokens[refreshToken] = true
    delete(authCodes, state)
    delete(states, state)
    mutex.Unlock()

    json.NewEncoder(w).Encode(map[string]string{
        "access_token":  accessToken,
        "refresh_token": refreshToken,
        "expires_in":    "3600",
    })
}

func revokeHandler(w http.ResponseWriter, r *http.Request) {
    token := r.FormValue("token")
    mutex.Lock()
    delete(tokens, token)
    mutex.Unlock()
}

func generatePKCECodeChallenge(verifier string) string {
    hash := sha256.Sum256([]byte(verifier))
    return base64.RawURLEncoding.EncodeToString(hash[:])
}

func generateRandomString(length int) string {
    b := make([]byte, length)
    rand.Read(b)
    return base64.RawURLEncoding.EncodeToString(b)
}

func auditLog(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        next.ServeHTTP(w, r)
        fmt.Printf("[%s] %s %s %s\n", time.Now().UTC(), r.Method, r.URL.Path, r.RemoteAddr)
    })
}

func enforceTLS(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        if r.TLS == nil {
            http.Redirect(w, r, "https://"+r.Host+r.RequestURI, http.StatusMovedPermanently)
            return
        }
        next.ServeHTTP(w, r)
    })
}

func rateLimit(perSec int) func(http.Handler) http.Handler {
    limiter := rate.NewLimiter(rate.Limit(perSec), perSec*10)
    return func(next http.Handler) http.Handler {
        return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
            if !limiter.Allow() {
                http.Error(w, "too many requests", http.StatusTooManyRequests)
                return
            }
            next.ServeHTTP(w, r)
        })
    }
}
