#include <iostream>
#include <fstream>
#include <vector>
#include <algorithm>
#include <thread>
#include <queue>
#include <filesystem>
#include <chrono>
#include <execution>

namespace fs = std::filesystem;
const size_t RAM_LIMIT = 6ULL * 1024 * 1024 * 1024; // 6GB per chunk
const size_t BUFFER_SIZE = 10 * 1024 * 1024; // 10MB buffer
using uint64 = unsigned long long;

struct FileBuffer {
    std::ifstream file;
    std::vector<uint64> buffer;
    size_t pos;
    bool eof;

    FileBuffer(const std::string& path) : file(path, std::ios::binary), pos(0), eof(false) {
        buffer.resize(BUFFER_SIZE / sizeof(uint64));
        refill();
    }

    void refill() {
        file.read(reinterpret_cast<char*>(buffer.data()), BUFFER_SIZE);
        size_t bytes = file.gcount();
        if (bytes < BUFFER_SIZE) eof = true;
        buffer.resize(bytes / sizeof(uint64));
        pos = 0;
    }

    uint64 current() const { return buffer[pos]; }
    void next() { 
        if (++pos >= buffer.size() && !eof) refill();
    }
    bool done() const { return eof && pos >= buffer.size(); }
};

void sort_chunk(const std::string& in_path, size_t start, size_t end, const std::string& out_path) {
    std::ifstream in(in_path, std::ios::binary);
    in.seekg(start);
    size_t size = end - start;
    std::vector<uint64> data(size / sizeof(uint64));
    in.read(reinterpret_cast<char*>(data.data()), size);
    in.close();

    std::sort(std::execution::par, data.begin(), data.end());

    std::ofstream out(out_path, std::ios::binary);
    out.write(reinterpret_cast<const char*>(data.data()), size);
    out.close();
}

void merge(const std::vector<std::string>& paths, const std::string& out_path) {
    std::vector<FileBuffer> buffers;
    for (const auto& p : paths) buffers.emplace_back(p);

    auto cmp = [](const FileBuffer* a, const FileBuffer* b) { return a->current() > b->current(); };
    std::priority_queue<FileBuffer*, std::vector<FileBuffer*>, decltype(cmp)> pq(cmp);
    for (auto& b : buffers) if (!b.done()) pq.push(&b);

    std::ofstream out(out_path, std::ios::binary);
    std::vector<uint64> out_buf;
    out_buf.reserve(BUFFER_SIZE / sizeof(uint64));

    while (!pq.empty()) {
        FileBuffer* b = pq.top();
        pq.pop();
        out_buf.push_back(b->current());
        if (out_buf.size() == out_buf.capacity()) {
            out.write(reinterpret_cast<const char*>(out_buf.data()), out_buf.size() * sizeof(uint64));
            out_buf.clear();
        }
        b->next();
        if (!b->done()) pq.push(b);
    }

    if (!out_buf.empty()) 
        out.write(reinterpret_cast<const char*>(out_buf.data()), out_buf.size() * sizeof(uint64));
    out.close();
}

void external_sort(const std::string& input_path, const std::string& output_path) {
    std::vector<std::string> chunks;
    size_t file_size = fs::file_size(input_path);
    size_t chunk_size = RAM_LIMIT;

    // Phase 1: Sort chunks
    auto phase1_start = std::chrono::high_resolution_clock::now();
    std::vector<std::thread> threads;
    for (size_t offset = 0; offset < file_size; offset += chunk_size) {
        size_t end = std::min(offset + chunk_size, file_size);
        std::string chunk_path = "chunk_" + std::to_string(offset) + ".bin";
        chunks.push_back(chunk_path);
        threads.emplace_back(sort_chunk, input_path, offset, end, chunk_path);
    }
    for (auto& t : threads) t.join();
    auto phase1_end = std::chrono::high_resolution_clock::now();

    // Phase 2: Merge chunks
    auto phase2_start = std::chrono::high_resolution_clock::now();
    while (chunks.size() > 1) {
        std::vector<std::string> new_chunks;
        std::vector<std::thread> merge_threads;
        for (size_t i = 0; i < chunks.size(); i += 8) {
            auto end = std::min(i + 8, chunks.size());
            std::vector<std::string> group(chunks.begin() + i, chunks.begin() + end);
            std::string merged = "merged_" + std::to_string(i) + ".bin";
            new_chunks.push_back(merged);
            merge_threads.emplace_back([group, merged]() { merge(group, merged); });
        }
        for (auto& t : merge_threads) t.join();
        for (const auto& f : chunks) fs::remove(f);
        chunks = new_chunks;
    }
    fs::rename(chunks[0], output_path);
    auto phase2_end = std::chrono::high_resolution_clock::now();

    // Benchmark output
    std::cout << "Phase 1 time: " 
              << std::chrono::duration<double>(phase1_end - phase1_start).count() 
              << "s\nPhase 2 time: " 
              << std::chrono::duration<double>(phase2_end - phase2_start).count() 
              << "s\n";
}

int main() {
    external_sort("input.bin", "output.bin");
    return 0;
}
