# framework.py
import abc
import importlib.metadata
from typing import Any, Dict, List, Optional

class Edge:
    def __init__(self, target: str, weight: float):
        self.target = target
        self.weight = weight

class Graph:
    def __init__(self):
        self.nodes: Dict[str, Dict[str, Any]] = {}
        self.edges: Dict[str, List[Edge]] = {}

    def add_node(self, node_id: str, **attrs):
        self.nodes[node_id] = attrs

    def add_edge(self, source: str, target: str, weight: float):
        self.edges.setdefault(source, []).append(Edge(target, weight))

class PathfindingPlugin(abc.ABC):
    @abc.abstractmethod
    def find_path(self, graph: Graph, start: str, end: str) -> Optional[List[str]]:
        pass

class PluginManager:
    def __init__(self):
        self.plugins = self._load_plugins()

    def _load_plugins(self) -> Dict[str, PathfindingPlugin]:
        plugins = {}
        for entry_point in importlib.metadata.entry_points().get('graph_search.plugins', []):
            plugin_class = entry_point.load()
            plugins[entry_point.name] = plugin_class()
        return plugins

    def get_plugin(self, name: str) -> PathfindingPlugin:
        return self.plugins[name]

# dijkstra.py (sample plugin)
import heapq
from framework import PathfindingPlugin, Graph

class Dijkstra(PathfindingPlugin):
    def find_path(self, graph: Graph, start: str, end: str) -> Optional[List[str]]:
        pq = []
        heapq.heappush(pq, (0, start))
        came_from = {}
        cost_so_far = {node: float('inf') for node in graph.nodes}
        cost_so_far[start] = 0

        while pq:
            current_cost, current = heapq.heappop(pq)
            if current == end:
                path = []
                while current in came_from:
                    path.append(current)
                    current = came_from[current]
                path.append(start)
                return path[::-1]

            for edge in graph.edges.get(current, []):
                new_cost = current_cost + edge.weight
                if new_cost < cost_so_far[edge.target]:
                    cost_so_far[edge.target] = new_cost
                    heapq.heappush(pq, (new_cost, edge.target))
                    came_from[edge.target] = current
        return None

