import java.util.*;
import java.util.concurrent.*;
import java.util.regex.*;

public class PIIMasker {
    private static class PIIPattern {
        Pattern regex;
        String type;
        Set<String> keywords;
        double boost;

        PIIPattern(String regex, String type, Set<String> keywords, double boost) {
            this.regex = Pattern.compile(regex, Pattern.CASE_INSENSITIVE | Pattern.UNICODE_CASE);
            this.type = type;
            this.keywords = keywords;
            this.boost = boost;
        }
    }

    private static final List<PIIPattern> PATTERNS = Arrays.asList(
        new PIIPattern("\\b[A-Z0-9_%+-]+@[A-Z0-9.-]+\\.[A-Z]{2,6}\\b", "EMAIL", Set.of("email", "e-mail"), 0.3),
        new PIIPattern("\\b\\d{3}[-.]?\\d{3}[-.]?\\d{4}\\b", "PHONE", Set.of("phone", "mobile"), 0.2),
        new PIIPattern("\\b\\d{3}-\\d{2}-\\d{4}\\b", "SSN", Set.of("ssn", "social"), 0.4)
    );

    public String mask(String text) {
        List<MatchResult> results = new ArrayList<>();
        ExecutorService executor = Executors.newCachedThreadPool();

        for (PIIPattern p : PATTERNS) {
            Matcher matcher = p.regex.matcher(text);
            Future<?> future = executor.submit(() -> {
                while (matcher.find()) {
                    int start = matcher.start();
                    int end = matcher.end();
                    double confidence = 0.5;
                    String context = text.substring(Math.max(0, start - 50), start).toLowerCase();
                    for (String kw : p.keywords) {
                        if (context.contains(kw)) {
                            confidence += p.boost;
                            break;
                        }
                    }
                    results.add(new MatchResult(start, end, p.type, confidence));
                }
            });
            try {
                future.get(100, TimeUnit.MILLISECONDS);
            } catch (TimeoutException e) {
                future.cancel(true);
            } catch (Exception e) {}
        }

        executor.shutdown();
        results.sort((a, b) -> b.start - a.start);
        StringBuilder masked = new StringBuilder(text);
        for (MatchResult mr : results) {
            masked.replace(mr.start, mr.end, String.format("[REDACTED_%s]", mr.type));
        }
        return masked.toString();
    }

    private static class MatchResult {
        int start, end;
        String type;
        double confidence;
        MatchResult(int s, int e, String t, double c) {
            start = s; end = e; type = t; confidence = c;
        }
    }
}
