// lib.rs
use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq)]
pub struct Item {
    pub value: u32,
    pub weight: u32,
}

pub trait KnapsackSolver {
    fn solve(&self, items: &[Item], capacity: u32) -> u32;
}

pub struct DynamicProgramming;

impl KnapsackSolver for DynamicProgramming {
    fn solve(&self, items: &[Item], capacity: u32) -> u32 {
        let capacity = capacity as usize;
        let mut dp = vec![0; capacity + 1];

        for item in items {
            for w in (item.weight as usize..=capacity).rev() {
                dp[w] = dp[w].max(dp[w - item.weight as usize] + item.value);
            }
        }

        dp[capacity]
    }
}

pub struct BranchAndBound;

impl KnapsackSolver for BranchAndBound {
    fn solve(&self, items: &[Item], capacity: u32) -> u32 {
        let mut items = items.to_vec();
        items.sort_by(|a, b| (b.value * a.weight).cmp(&(a.value * b.weight)));

        let mut best = 0;
        let mut queue = std::collections::BinaryHeap::new();
        queue.push(Node::root(&items, capacity));

        while let Some(node) = queue.pop() {
            if node.upper_bound <= best || node.index >= items.len() {
                continue;
            }

            if node.current_value > best {
                best = node.current_value;
            }

            let item = &items[node.index];
            if node.current_weight + item.weight <= capacity {
                queue.push(Node::with_item(&node, &items, capacity));
            }

            queue.push(Node::without_item(&node, &items, capacity));
        }

        best
    }
}

struct Node {
    current_value: u32,
    current_weight: u32,
    upper_bound: u32,
    index: usize,
}

impl Node {
    fn root(items: &[Item], capacity: u32) -> Self {
        let upper_bound = Node::calculate_upper_bound(0, 0, 0, items, capacity);
        Node {
            current_value: 0,
            current_weight: 0,
            upper_bound,
            index: 0,
        }
    }

    fn with_item(parent: &Node, items: &[Item], capacity: u32) -> Self {
        let item = &items[parent.index];
        let current_value = parent.current_value + item.value;
        let current_weight = parent.current_weight + item.weight;
        let upper_bound = Node::calculate_upper_bound(
            current_value,
            current_weight,
            parent.index + 1,
            items,
            capacity,
        );
        Node {
            current_value,
            current_weight,
            upper_bound,
            index: parent.index + 1,
        }
    }

    fn without_item(parent: &Node, items: &[Item], capacity: u32) -> Self {
        let upper_bound = Node::calculate_upper_bound(
            parent.current_value,
            parent.current_weight,
            parent.index + 1,
            items,
            capacity,
        );
        Node {
            current_value: parent.current_value,
            current_weight: parent.current_weight,
            upper_bound,
            index: parent.index + 1,
        }
    }

    fn calculate_upper_bound(
        current_value: u32,
        current_weight: u32,
        index: usize,
        items: &[Item],
        capacity: u32,
    ) -> u32 {
        let mut bound = current_value;
        let mut remaining_weight = capacity - current_weight;
        let mut j = index;

        while j < items.len() && items[j].weight <= remaining_weight {
            bound += items[j].value;
            remaining_weight -= items[j].weight;
            j += 1;
        }

        if j < items.len() {
            bound += (remaining_weight * items[j].value / items[j].weight) as u32;
        }

        bound
    }
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        self.upper_bound.cmp(&other.upper_bound)
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl PartialEq for Node {
    fn eq(&self, other: &Self) -> bool {
        self.upper_bound == other.upper_bound
    }
}

impl Eq for Node {}

pub struct Greedy;

impl KnapsackSolver for Greedy {
    fn solve(&self, items: &[Item], capacity: u32) -> u32 {
        let mut items = items.to_vec();
        items.sort_by(|a, b| {
            (b.value as f64 / b.weight as f64)
                .partial_cmp(&(a.value as f64 / a.weight as f64))
                .unwrap_or(Ordering::Equal)
        });

        let mut remaining = capacity;
        let mut total = 0;

        for item in items {
            if item.weight <= remaining {
                total += item.value;
                remaining -= item.weight;
            }
        }

        total
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;

    #[test]
    fn empty_knapsack() {
        let solvers: Vec<Box<dyn KnapsackSolver>> = vec![
            Box::new(DynamicProgramming),
            Box::new(BranchAndBound),
            Box::new(Greedy),
        ];
        for solver in solvers {
            assert_eq!(solver.solve(&[], 10), 0);
        }
    }

    #[test]
    fn zero_capacity() {
        let items = vec![Item { value: 10, weight: 5 }];
        let solvers: Vec<Box<dyn KnapsackSolver>> = vec![
            Box::new(DynamicProgramming),
            Box::new(BranchAndBound),
            Box::new(Greedy),
        ];
        for solver in solvers {
            assert_eq!(solver.solve(&items, 0), 0);
        }
    }

    proptest! {
        #[test]
        fn all_solvers_agree(items in any::<Vec<(u32, u32)>>().prop_map(|v| v.into_iter().map(|(v, w)| Item { value: v % 100, weight: w % 100 }).collect::<Vec<_>>()),
                             capacity in 0..1000u32) {
            let dp = DynamicProgramming;
            let bnb = BranchAndBound;
            let greedy = Greedy;

            let dp_result = dp.solve(&items, capacity);
            let bnb_result = bnb.solve(&items, capacity);
            let greedy_result = greedy.solve(&items, capacity);

            assert_eq!(dp_result, bnb_result);
            assert!(greedy_result <= dp_result);
        }
    }
}
