```go
package main

import (
	"fmt"
	"log"
	"math/rand"
	"sync"
	"time"
)

// Node represents a Raft node
type Node struct {
	ID        int
	state     string
	currentTerm int
	votedFor  int
	log       []LogEntry
	commitIndex int
	nextIndex  []int
	matchIndex []int

	peers      []*Node
	network    *Network
	serverChan chan Message
	stopChan   chan struct{}
	mu         sync.Mutex
}

// Network simulates network conditions
type Network struct {
	nodes       map[int]*Node
	partitions  map[int]bool
	dropRate    float64
	latency     time.Duration
	mu          sync.Mutex
}

// Message represents RPC message
type Message struct {
	Type    string
	From    int
	To      int
	Term    int
	Success bool
}

// LogEntry represents log entry
type LogEntry struct {
	Term    int
	Command interface{}
}

// StateTransition log
type StateTransition struct {
	NodeID    int
	OldState  string
	NewState  string
	Timestamp time.Time
}

var transitionLog []StateTransition

func (n *Node) run() {
	electionTimeout := time.Duration(150+rand.Intn(150)) * time.Millisecond
	ticker := time.NewTicker(electionTimeout)
	defer ticker.Stop()

	for {
		select {
		case msg := <-n.serverChan:
			n.handleMessage(msg)
		case <-ticker.C:
			if n.state != "leader" {
				n.startElection()
			}
		case <-n.stopChan:
			return
		}
	}
}

func (n *Node) startElection() {
	n.mu.Lock()
	defer n.mu.Unlock()

	n.currentTerm++
	n.state = "candidate"
	n.votedFor = n.ID
	logTransition(n.ID, "follower", "candidate")

	votes := 1
	for _, peer := range n.peers {
		if n.network.IsPartitioned(peer.ID) {
			continue
		}
		// Simulate RequestVote RPC
		if rand.Float64() > n.network.dropRate {
			n.network.Send(Message{
				Type: "RequestVote",
				From: n.ID,
				To:   peer.ID,
				Term: n.currentTerm,
			})
		}
	}

	if votes > len(n.peers)/2 {
		n.becomeLeader()
	}
}

func (n *Node) becomeLeader() {
	n.state = "leader"
	logTransition(n.ID, "candidate", "leader")

	// Start periodic heartbeats
	go func() {
		heartbeat := time.NewTicker(50 * time.Millisecond)
		defer heartbeat.Stop()
		for n.state == "leader" {
			<-heartbeat.C
			n.sendHeartbeats()
		}
	}()
}

func (n *Network) Send(msg Message) {
	n.mu.Lock()
	defer n.mu.Unlock()

	if n.partitions[msg.From] || n.partitions[msg.To] {
		return
	}

	if rand.Float64() < n.dropRate {
		return
	}

	time.AfterFunc(n.latency, func() {
		if node, ok := n.nodes[msg.To]; ok {
			node.serverChan <- msg
		}
	})
}

func (n *Network) IsPartitioned(nodeID int) bool {
	return n.partitions[nodeID]
}

func logTransition(nodeID int, oldState, newState string) {
	transitionLog = append(transitionLog, StateTransition{
		NodeID:    nodeID,
		OldState:  oldState,
		NewState:  newState,
		Timestamp: time.Now(),
	})
}

// Fault injection methods
func (n *Network) Partition(nodeID int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	n.partitions[nodeID] = true
}

func (n *Network) Heal(nodeID int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	delete(n.partitions, nodeID)
}

func (n *Network) Crash(nodeID int) {
	n.mu.Lock()
	defer n.mu.Unlock()
	if node, ok := n.nodes[nodeID]; ok {
		close(node.stopChan)
		delete(n.nodes, nodeID)
	}
}

// Test cases
func TestLeaderElection() {
	network := &Network{
		nodes:      make(map[int]*Node),
		partitions: make(map[int]bool),
		dropRate:   0.3,
		latency:    10 * time.Millisecond,
	}

	// Create 5 nodes
	for i := 0; i < 5; i++ {
		node := &Node{
			ID:          i,
			state:       "follower",
			serverChan:  make(chan Message, 100),
			stopChan:    make(chan struct{}),
			network:     network,
		}
		network.nodes[i] = node
		go node.run()
	}

	// Simulate network partition and recovery
	network.Partition(0)
	network.Heal(0)

	// Crash a leader and verify re-election
	network.Crash(2)
}

func main() {
	rand.Seed(time.Now().UnixNano())
	TestLeaderElection()
}
