let speed = 500;
let svg = d3.select('svg');
let timeout;

function initialize() {
    data = d3.range(50).map(() => Math.random() * 380 + 20);
    svg.selectAll('rect').data(data).join('rect')
        .attr('class', 'bar')
        .attr('x', (d,i) => i * 16)
        .attr('y', d => 400 - d)
        .attr('width', 15)
        .attr('height', d => d);
}

function* mergeSort(arr, l=0, r=arr.length-1) {
    if (l >= r) return;
    const m = Math.floor((l + r) / 2);
    yield* mergeSort(arr, l, m);
    yield* mergeSort(arr, m+1, r);
    yield* merge(arr, l, m, r);
}

function* merge(arr, l, m, r) {
    let result = [];
    let i = l, j = m+1;
    while (i <= m && j <= r) {
        if (arr[i] <= arr[j]) result.push(arr[i++]);
        else result.push(arr[j++]);
    }
    while (i <= m) result.push(arr[i++]);
    while (j <= r) result.push(arr[j++]);

    for (let k = 0; k < result.length; k++) {
        arr[l + k] = result[k];
        yield {action: "merge", index: l + k, value: result[k]};
    }
}

document.getElementById('start').addEventListener('click', () => {
    if (!isSorting) {
        isSorting = true;
        runSort();
    }
});

document.getElementById('pause').addEventListener('click', () => isSorting = false);
document.getElementById('step').addEventListener('click', () => generator.next());
document.getElementById('speed').addEventListener('input', e => speed = 1000 - e.target.value);

function runSort() {
    if (!isSorting) return;
    let step = generator.next();
    if (!step.done) {
        updateVisualization(step.value);
        timeout = setTimeout(runSort, speed);
    } else {
        isSorting = false;
    }
}

function updateVisualization(state) {
    svg.selectAll('rect')
        .attr('fill', (d,i) => i === state.index ? 'orange' : 'steelblue');
    document.getElementById('annotation').textContent = 
        `${state.action} at index ${state.index}`;
}

initialize();
</script>
