#include <immintrin.h>
#include <x86intrin.h>
#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <fftw3.h>

#define N (1 << 20)
#define ALIGN 32

typedef struct { double real, imag; } complex_d;

static inline __m256d _mm256_complex_mul(__m256d a, __m256d b) {
    __m256d b_flip = _mm256_permute_pd(b, 0x5);
    __m256d a_im = _mm256_permute_pd(a, 0xF);
    __m256d a_re = _mm256_permute_pd(a, 0x0);
    __m256d re = _mm256_mul_pd(a_re, b);
    __m256d im = _mm256_mul_pd(a_im, b_flip);
    return _mm256_addsub_pd(re, im);
}

void fft_avx(complex_d* x) {
    complex_d* twiddle = _mm_malloc(N * sizeof(complex_d), ALIGN);
    int log2n = log2(N);

    for (int i = 0; i < N; i++) {
        int rev = 0;
        for (int j = 0; j < log2n; j++) 
            rev |= ((i >> j) & 1) << (log2n - 1 - j);
        if (i < rev) {
            complex_d tmp = x[i];
            x[i] = x[rev];
            x[rev] = tmp;
        }
    }

    for (int s = 1; s <= log2n; s++) {
        int m = 1 << s;
        int m2 = m >> 1;
        double theta = 2 * M_PI / m;

        for (int i = 0; i < m2; i++) {
            twiddle[i].real = cos(i * theta);
            twiddle[i].imag = -sin(i * theta);
        }

        for (int k = 0; k < N; k += m) {
            for (int j = 0; j < m2; j += 2) {
                __m256d w = _mm256_setr_pd(twiddle[j].real, twiddle[j].imag,
                                           twiddle[j+1].real, twiddle[j+1].imag);
                complex_d* x0 = x + k + j;
                complex_d* x1 = x + k + j + m2;
                __m256d d0 = _mm256_load_pd((double*)x0);
                __m256d d1 = _mm256_load_pd((double*)x1);
                __m256d t = _mm256_complex_mul(d1, w);
                __m256d sum = _mm256_add_pd(d0, t);
                __m256d diff = _mm256_sub_pd(d0, t);
                _mm256_store_pd((double*)x0, sum);
                _mm256_store_pd((double*)x1, diff);
            }
        }
    }
    _mm_free(twiddle);
}

int main() {
    complex_d* data = _mm_malloc(N * sizeof(complex_d), ALIGN);
    for (int i = 0; i < N; i++) {
        data[i].real = (double)rand() / RAND_MAX;
        data[i].imag = (double)rand() / RAND_MAX;
    }

    unsigned long long start = __rdtsc();
    fft_avx(data);
    unsigned long long cycles = __rdtsc() - start;
    printf("Custom FFT cycles: %llu\n", cycles);

    fftw_complex* in = (fftw_complex*)fftw_malloc(N * sizeof(fftw_complex));
    fftw_complex* out = (fftw_complex*)fftw_malloc(N * sizeof(fftw_complex));
    fftw_plan p = fftw_plan_dft_1d(N, in, out, FFTW_FORWARD, FFTW_ESTIMATE);

    start = __rdtsc();
    fftw_execute(p);
    cycles = __rdtsc() - start;
    printf("FFTW FFT cycles: %llu\n", cycles);

    _mm_free(data);
    fftw_destroy_plan(p);
    fftw_free(in);
    fftw_free(out);
    return 0;
}
