#include <atomic>
#include <iostream>
#include <vector>
#include <map>
#include <thread>
#include <chrono>
#include <boost/lockfree/queue.hpp>
#include <sched.h>

struct Order {
    enum Side { Buy, Sell };
    Side side;
    uint64_t id;
    double price;
    uint64_t quantity;
    bool matched = false;
};

class MemoryPool {
    std::vector<Order> pool;
    std::atomic<uint64_t> index{0};
public:
    MemoryPool(size_t size) : pool(size) {}
    Order* allocate() {
        return &pool[index++ % pool.size()];
    }
};

using OrderQueue = boost::lockfree::queue<Order*, boost::lockfree::capacity<65536>>;

class OrderBook {
    std::map<double, std::vector<Order*>> bids;
    std::map<double, std::vector<Order*>, std::greater<double>> asks;
public:
    void process(Order* order) {
        auto& opposite = (order->side == Order::Buy) ? asks : bids;
        auto& same = (order->side == Order::Buy) ? bids : asks;

        while (order->quantity > 0 && !opposite.empty()) {
            auto best = opposite.begin();
            auto& orders = best->second;
            while (!orders.empty() && order->quantity > 0) {
                Order* opposite_order = orders.back();
                uint64_t fill = std::min(order->quantity, opposite_order->quantity);
                order->quantity -= fill;
                opposite_order->quantity -= fill;
                if (opposite_order->quantity == 0) {
                    orders.pop_back();
                    opposite_order->matched = true;
                }
                if (order->quantity == 0) order->matched = true;
            }
            if (orders.empty()) opposite.erase(best);
        }
        if (order->quantity > 0) same[order->price].push_back(order);
    }
};

void engine_thread(OrderQueue& queue, OrderBook& book, int cpu) {
    cpu_set_t cpuset;
    CPU_ZERO(&cpuset);
    CPU_SET(cpu, &cpuset);
    pthread_setaffinity_np(pthread_self(), sizeof(cpu_set_t), &cpuset);

    Order* order;
    while (true) {
        while (queue.pop(order)) book.process(order);
    }
}

int main() {
    constexpr size_t N = 1000000;
    MemoryPool pool(N);
    OrderQueue queue;
    OrderBook book;

    std::thread engine(engine_thread, std::ref(queue), std::ref(book), 0);

    auto start = std::chrono::high_resolution_clock::now();
    for (uint64_t i = 0; i < N; ++i) {
        Order* order = pool.allocate();
        order->id = i;
        order->side = i % 2 ? Order::Sell : Order::Buy;
        order->price = 100.0 + (i % 10);
        order->quantity = 100;
        while (!queue.push(order)) {}
    }
    auto end = std::chrono::high_resolution_clock::now();
    auto us = std::chrono::duration_cast<std::chrono::microseconds>(end - start).count();
    std::cout << "Processed " << N << " orders in " << us << "μs\n";

    engine.detach();
    return 0;
}
