// WebhookInterceptor.java
public class WebhookInterceptor implements HandlerInterceptor {
    private static final String HMAC_SECRET = "your-secret-key";
    private static final String HMAC_HEADER = "X-Signature";

    @Override
    public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception {
        String signature = request.getHeader(HMAC_HEADER);
        String body = new BufferedReader(new InputStreamReader(request.getInputStream())).lines()
            .collect(Collectors.joining("\n"));

        Mac sha256 = Mac.getInstance("HmacSHA256");
        sha256.init(new SecretKeySpec(HMAC_SECRET.getBytes(), "HmacSHA256"));
        byte[] computedSignature = sha256.doFinal(body.getBytes());

        if (!MessageDigest.isEqual(computedSignature, HexFormat.of().parseHex(signature))) {
            response.sendError(HttpStatus.UNAUTHORIZED.value());
            return false;
        }
        return true;
    }
}

