```rust
use rumqttc::{AsyncClient, Event, MqttOptions, QoS, Transport};
use serde::{Deserialize, Serialize};
use std::{
    collections::BTreeSet,
    path::PathBuf,
    sync::Arc,
    time::{Duration, SystemTime},
};
use tokio::{
    fs::{File, OpenOptions},
    io::{AsyncBufReadExt, AsyncWriteExt, BufReader},
    sync::Mutex,
    time,
};
use warp::Filter;

#[derive(Serialize, Deserialize, Clone, Debug)]
struct Telemetry {
    device_id: String,
    sequence: u64,
    payload: Vec<u8>,
}

struct Wal {
    file: File,
    path: PathBuf,
}

impl Wal {
    async fn new(path: PathBuf) -> Self {
        let file = OpenOptions::new()
            .create(true)
            .append(true)
            .open(&path)
            .await
            .unwrap();
        Wal { file, path }
    }

    async fn append(&mut self, data: &[u8]) {
        self.file.write_all(data).await.unwrap();
        self.file.write_all(b"\n").await.unwrap();
    }

    async fn recover(path: PathBuf) -> Vec<Vec<u8>> {
        let file = OpenOptions::new().read(true).open(&path).await.unwrap();
        let reader = BufReader::new(file);
        let mut lines = reader.lines();
        let mut entries = Vec::new();

        while let Some(line) = lines.next_line().await.unwrap() {
            entries.push(line.into_bytes());
        }
        entries
    }
}

struct HealthState {
    last_activity: SystemTime,
    wal_ok: bool,
    connected: bool,
}

#[tokio::main]
async fn main() {
    let mqtt_opts = MqttOptions::new("iot-ingest", "broker.example.com", 1883)
        .set_transport(Transport::tcp())
        .set_keep_alive(Duration::from_secs(5));

    let (client, mut eventloop) = AsyncClient::new(mqtt_opts, 10);
    let wal = Wal::new(PathBuf::from("telemetry.wal")).await;
    let wal = Arc::new(Mutex::new(wal));

    let processed = Arc::new(Mutex::new(BTreeSet::new()));
    let health_state = Arc::new(Mutex::new(HealthState {
        last_activity: SystemTime::now(),
        wal_ok: true,
        connected: false,
    }));

    let health_check = health_router(health_state.clone());
    tokio::spawn(warp::serve(health_check).run(([0, 0, 0, 0], 8080)));

    let client_clone = client.clone();
    tokio::spawn(async move {
        let mut backoff = 1;
        loop {
            match eventloop.poll().await {
                Ok(event) => match event {
                    Event::Incoming(packet) => {
                        let mut health = health_state.lock().await;
                        health.last_activity = SystemTime::now();

                        if let rumqttc::Packet::Publish(msg) = packet {
                            let telemetry: Telemetry = bincode::deserialize(&msg.payload).unwrap();
                            let mut processed_set = processed.lock().await;

                            if processed_set.insert(telemetry.sequence) {
                                let mut wal = wal.lock().await;
                                wal.append(&bincode::serialize(&telemetry).unwrap()).await;
                            }
                        }
                        health.connected = true;
                        backoff = 1;
                    }
                    _ => (),
                },
                Err(_) => {
                    time::sleep(Duration::from_secs(backoff)).await;
                    backoff = (backoff * 2).min(60);
                    let _ = client_clone.reconnect();
                }
            }
        }
    });

    client.subscribe("telemetry/#", QoS::ExactlyOnce).await.unwrap();
    time::sleep(Duration::MAX).await;
}

fn health_router(state: Arc<Mutex<HealthState>>) -> impl Filter<Extract = impl warp::Reply, Error = warp::Rejection> + Clone {
    warp::path("health").map(move || {
        let state = state.blocking_lock();
        if state.connected && state.wal_ok && state.last_activity.elapsed().unwrap().as_secs() < 10 {
            warp::reply::json(&serde_json::json!({"status": "ok"}))
        } else {
            warp::reply::with_status(
                warp::reply::json(&serde_json::json!({"status": "unhealthy"})),
                warp::http::StatusCode::SERVICE_UNAVAILABLE,
            )
        }
    })
}
