package main

import (
	"bytes"
	"context"
	"fmt"
	"os/exec"
	"sync"
	"time"
)

type TranscodeJob struct {
	Input      []byte
	ResultChan chan<- []byte
}

func worker(jobChan <-chan TranscodeJob, ctx context.Context) {
	for job := range jobChan {
		select {
		case <-ctx.Done():
			return
		default:
			cmd := exec.CommandContext(ctx,
				"ffmpeg",
				"-hwaccel", "cuda", "-hwaccel_output_format", "cuda",
				"-i", "pipe:0",
				"-vf", "scale_cuda=-2:720",
				"-c:v", "h264_nvenc",
				"-preset", "p6",
				"-tune", "ll",
				"-b:v", "3000k",
				"-maxrate", "3000k",
				"-bufsize", "6000k",
				"-f", "mp4",
				"pipe:1",
			)

			cmd.Stdin = bytes.NewReader(job.Input)
			var out bytes.Buffer
			cmd.Stdout = &out

			if err := cmd.Run(); err == nil {
				job.ResultChan <- out.Bytes()
			} else {
				job.ResultChan <- nil
			}
		}
	}
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 450*time.Millisecond)
	defer cancel()

	const numWorkers = 4
	jobChan := make(chan TranscodeJob, 100)
	var wg sync.WaitGroup

	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			worker(jobChan, ctx)
		}()
	}

	resultChan := make(chan []byte, 1)
	jobChan <- TranscodeJob{Input: []byte("dummy_video_chunk"), ResultChan: resultChan}
	<-resultChan

	close(jobChan)
	wg.Wait()
}
